<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      fullscreen
    >
      <v-card class="invoice-dialog">
        <!-- Header -->
        <div class="dialog-header">
          <div class="d-flex align-center justify-space-between px-5 py-4">
            <div class="d-flex align-center">
              <div class="header-icon me-3">
                <v-icon color="white" size="24">mdi-receipt-text-outline</v-icon>
              </div>
              <div>
                <h3 class="text-white">عناصر الفاتورة</h3>
                <p class="text-white mt-n1" style="opacity: 0.7; font-size: 0.8rem;">
                  عرض تفاصيل العناصر المباعة
                  <v-chip variant="tonal" color="white" size="x-small" class="ms-2">{{ items.length }} عنصر</v-chip>
                </p>
              </div>
            </div>
            <v-btn icon variant="text" @click="$emit('popClose')">
              <v-icon color="white" size="24">mdi-close</v-icon>
            </v-btn>
          </div>
        </div>

        <!-- Summary Cards -->
        <div class="summary-bar">
          <div class="summary-card">
            <v-icon color="primary" size="18" class="me-2">mdi-package-variant</v-icon>
            <div>
              <div class="summary-label">عدد العناصر</div>
              <div class="summary-value">{{ items.length }}</div>
            </div>
          </div>
          <div class="summary-card">
            <v-icon color="success" size="18" class="me-2">mdi-cart-check</v-icon>
            <div>
              <div class="summary-label">الكمية الكلية</div>
              <div class="summary-value">{{ totalQuantity }}</div>
            </div>
          </div>
          <div class="summary-card">
            <v-icon color="warning" size="18" class="me-2">mdi-undo-variant</v-icon>
            <div>
              <div class="summary-label">المسترجعة</div>
              <div class="summary-value">{{ totalReturned }}</div>
            </div>
          </div>
          <div class="summary-card summary-card--total">
            <v-icon color="white" size="18" class="me-2">mdi-cash-multiple</v-icon>
            <div>
              <div class="summary-label" style="color: rgba(255,255,255,0.8);">الإجمالي</div>
              <div class="summary-value" style="color: #fff;">{{ $filters.formatNumber(totalPrice) }} <small>د.ع</small></div>
            </div>
          </div>
        </div>

        <!-- Table -->
        <v-card class="invoice-table-card" flat>
          <v-data-table-server
            :headers="headers"
            :items="items"
            hide-default-footer
            fixed-header
            height="calc(100vh - 280px)"
            :mobile-breakpoint="0"
          >
            <template v-slot:item="{ item, index }">
              <tr class="invoice-row">
                <td class="text-center">
                  <span class="row-index">{{ index + 1 }}</span>
                </td>

                <td class="text-center">
                  <code class="barcode-badge">{{ item.barcode }}</code>
                </td>

                <td class="text-center font-weight-bold">
                  {{ item.product_name }}
                </td>

                <td class="text-center">
                  <v-swatches v-model="item.color" :disabled="true" />
                </td>

                <td class="text-center">
                  <v-chip size="small" color="primary" variant="tonal" class="font-weight-bold">
                    {{ item.size }}
                  </v-chip>
                </td>

                <td class="text-center">
                  <span class="qty-badge">{{ item.quantity }}</span>
                </td>

                <td class="text-center">
                  <v-chip
                    size="small"
                    :color="item.returned_quantity > 0 ? 'warning' : 'default'"
                    :variant="item.returned_quantity > 0 ? 'tonal' : 'text'"
                    class="font-weight-bold"
                  >
                    {{ item.returned_quantity || 0 }}
                  </v-chip>
                </td>

                <td class="text-center font-weight-bold">
                  <span class="price-text">
                    {{ $filters.formatNumber(item.price * (item.quantity - (item.returned_quantity || 0))) }}
                    <small class="currency">د.ع</small>
                  </span>
                </td>

                <td class="text-center">
                  <v-tooltip text="استرجاع" location="bottom">
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        variant="tonal"
                        color="warning"
                        size="small"
                        v-bind="props"
                        :disabled="item.returned_quantity === item.quantity"
                        @click="popRetrieveItems(item)"
                        :loading="loading && item.id === sale_item_id"
                      >
                        <v-icon size="20">mdi-undo-variant</v-icon>
                        <template v-slot:loader>
                          <span class="custom-loader"><v-icon color="warning">mdi-cached</v-icon></span>
                        </template>
                      </v-btn>
                    </template>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
        </v-card>
      </v-card>
    </v-dialog>

    <PopRetrieveItems
      :dialog="dialog_retrieve_items"
      :maxQuantity="max_quantity_retrieve"
      @retrieveQuantity="retrieveQuantity"
      @popClose="dialog_retrieve_items = false"
    />
  </v-row>
</template>

<script setup>
import { useSalesStore } from "@/stores/sales";
import { ref, computed, defineEmits } from "vue";
import PopRetrieveItems from "@/components/sales/PopRetrieveItems.vue";

const salesStore = useSalesStore();
const quantity = ref(null);
const sale_item_id = ref(null);
const max_quantity_retrieve = ref(1);
const dialog_retrieve_items = ref(false);

const emit = defineEmits(["itemUpdated"]);
const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  items: {
    type: Array,
    required: true,
  },
});

const loading = computed(() => salesStore.retrieve_loading);

const totalQuantity = computed(() =>
  props.items.reduce((sum, i) => sum + (i.quantity || 0), 0)
);
const totalReturned = computed(() =>
  props.items.reduce((sum, i) => sum + (i.returned_quantity || 0), 0)
);
const totalPrice = computed(() =>
  props.items.reduce(
    (sum, i) => sum + i.price * ((i.quantity || 0) - (i.returned_quantity || 0)),
    0
  )
);

const headers = [
  { title: "#", value: "index", align: "center", width: "60px", sortable: false },
  { title: "باركود", value: "barcode", align: "center", width: "150px" },
  { title: "المنتج", value: "name", align: "center", width: "160px" },
  { title: "اللون", value: "color", align: "center", width: "100px" },
  { title: "القياس", value: "size", align: "center", width: "100px" },
  { title: "الكمية", value: "quantity", align: "center", width: "90px" },
  { title: "المسترجعة", value: "returned_quantity", align: "center", width: "110px" },
  { title: "السعر", value: "price", align: "center", width: "160px" },
  { title: "العمليات", value: "operations", align: "center", width: "100px", sortable: false },
];

function popRetrieveItems(item) {
  sale_item_id.value = item.id;
  max_quantity_retrieve.value = item.quantity;
  dialog_retrieve_items.value = true;
}

function retrieveQuantity(retrieve_quantity) {
  quantity.value = retrieve_quantity;
  retrieve();
}

const retrieve = async () => {
  let data = {
    sale_item_id: sale_item_id.value,
    quantity: quantity.value,
  };

  try {
    const response = await salesStore.retrieve_item(data);
    emit("itemUpdated", response.data.result[0]);
  } catch (e) {
    console.error("Error in store", e);
  }
};
</script>

<style scoped>
.invoice-dialog {
  background: #f5f3fa;
  border-radius: 0 !important;
}

.dialog-header {
  background: linear-gradient(135deg, #624fc6 0%, #1f2544 100%);
  position: sticky;
  top: 0;
  z-index: 10;
}

.header-icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
}

/* ─── Summary Bar ─── */
.summary-bar {
  display: flex;
  gap: 14px;
  padding: 18px 28px;
  flex-wrap: wrap;
}
.summary-card {
  display: flex;
  align-items: center;
  background: #fff;
  border: 1px solid rgba(98, 79, 198, 0.1);
  border-radius: 14px;
  padding: 12px 20px;
  min-width: 160px;
  flex: 1;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.04);
}
.summary-card--total {
  background: linear-gradient(135deg, #624fc6, #4a3a9e);
  border-color: transparent;
}
.summary-label {
  font-size: 0.72rem;
  font-weight: 600;
  color: #8b87a0;
  line-height: 1.2;
}
.summary-value {
  font-size: 1.1rem;
  font-weight: 800;
  color: #1a1a2e;
  line-height: 1.3;
}

/* ─── Table Card ─── */
.invoice-table-card {
  margin: 0 20px 20px;
  border-radius: 16px !important;
  border: 1px solid rgba(98, 79, 198, 0.08);
  overflow: hidden;
}

.invoice-row td {
  padding: 10px 12px !important;
  border-bottom: 1px solid rgba(0, 0, 0, 0.04);
}
.invoice-row:hover td {
  background: #faf9fe;
}

.row-index {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: #f0ecfa;
  color: #624fc6;
  font-weight: 800;
  font-size: 0.78rem;
  border-radius: 8px;
}

.barcode-badge {
  background: #f5f3fa;
  color: #1a1a2e;
  padding: 4px 10px;
  border-radius: 8px;
  font-weight: 700;
  font-size: 0.82rem;
  letter-spacing: 0.5px;
}

.qty-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 32px;
  height: 28px;
  background: linear-gradient(135deg, #624fc6, #4a3a9e);
  color: white;
  font-weight: 800;
  font-size: 0.82rem;
  border-radius: 8px;
  padding: 0 8px;
}

.price-text {
  color: #1a1a2e;
  font-size: 0.92rem;
}
.currency {
  color: #8b87a0;
  font-weight: 600;
  font-size: 0.72rem;
}

.custom-loader {
  animation: loader 1s infinite;
  display: flex;
}
@keyframes loader {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@media (max-width: 960px) {
  .summary-bar {
    padding: 12px 14px;
    gap: 8px;
  }
  .summary-card {
    min-width: 0;
    padding: 10px 12px;
    flex: 1 1 calc(50% - 8px);
  }
  .summary-value {
    font-size: 0.95rem;
  }
  .invoice-table-card {
    margin: 0 10px 10px;
    border-radius: 12px !important;
  }
}

@media (max-width: 600px) {
  .summary-bar {
    padding: 10px 10px;
    gap: 6px;
  }
  .summary-card {
    padding: 8px 10px;
    border-radius: 10px;
  }
  .summary-label {
    font-size: 0.65rem;
  }
  .summary-value {
    font-size: 0.85rem;
  }
  .invoice-table-card {
    margin: 0 6px 6px;
  }
}
</style>
