<template>
  <v-row justify="center">
    <v-dialog
      max-width="550"
      :model-value="dialog"
      transition="dialog-bottom-transition"
      opacity="0.15"
      persistent
    >
      <v-card class="mx-auto card" width="100%">
        <v-card-title>
          <v-btn
            icon
            fab
            x-small
            @click="$emit('popClose')"
            class="btn-transparent"
            style="box-shadow: 0px 0px 0px 0px"
          >
            <v-icon color="#000000" size="25">mdi-close</v-icon>
          </v-btn>

          <span style="display: flex; flex-direction: column; line-height: 1.5">
            <span style="display: flex; align-items: center; gap: 0px">
              <v-icon color="#624fc6" size="30">mdi-credit-card</v-icon>
              <h4 class="mr-3">تسجيل دفعة نقدية جديدة</h4>
            </span>
          </span>
        </v-card-title>

        <v-card-title class="gradient-red-card mx-4 my-4 py-5">
          <span style="display: flex; flex-direction: column; line-height: 1.5">
            <span style="display: flex; align-items: center; gap: 0px">
              <v-icon color="#000000" size="24" class="ml-2">mdi-alert</v-icon>
              <h5 style="font-weight: 400; color: #991b1b" class="">
                إجمالي المبلغ المستحق: {{ $filters.formatNumber(amount) }} د.ع
              </h5>
            </span>

            <h5 style="font-weight: 400; color: #991b1b" class="mr-8 mt-1">
              ملاحظة : توزيع تلقائي على الفواتير (الأقدم أولاً)
            </h5>
          </span>
        </v-card-title>
        <v-card-title class="pb-7">
          <h5 style="color: #7e22ce; font-weight: 400" class="py-2">
            المبلغ المدفوع *
          </h5>
          <span>
            <v-col col="12" sm="12" md="12" lg="12" class="pa-0 ma-0">
              <v-text-field
                :model-value="displayPrice"
                density="compact"
                class="font-weight-black custom-input2"
                type="text"
                placeholder="ادخل المبلغ المستلم"
                color="#624fc6"
                single-line
                variant="outlined"
                clearable
                lazy-rules
                persistent-hint
                hide-details="auto"
                @update:modelValue="onInput"
                @keypress="allowOnlyNumbers"
            /></v-col>
          </span>

          <span
            style="display: flex; align-items: center; gap: 0px"
            class="mt-5"
          >
            <v-btn
              fab
              variant="text"
              class="custom-button-1"
              @click="payments_value('all')"
              ><h4>دفع الكل ({{ $filters.formatNumber(amount) }})</h4></v-btn
            >
            <v-btn
              fab
              variant="text"
              class="custom-button-2 mr-2"
              @click="payments_value('half')"
              ><h4>
                نصف المبلغ ({{ $filters.formatNumber(amount / 2) }})
              </h4></v-btn
            >
          </span>

          <v-btn
            fab
            variant="text"
            class="button-add-payment mt-6"
            block
            @click="add_payment()"
          >
            <!-- :loading="loading" -->
            <v-icon color="#ffffff" size="24" class="ml-2">mdi-credit-card</v-icon>

            <h4 style="color: #ffffff">تسجيل دفعة</h4>
          </v-btn>
        </v-card-title>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
//  watch, onBeforeUnmount, computed
import { ref, computed, defineEmits } from "vue";

const emit = defineEmits(["addPayment"]);
const payment_value = ref(null);
const props = defineProps({
  dialog: { type: Boolean, default: false },
  amount: { type: [String, Number], default: 0 },
});

const displayPrice = computed(() => {
  if (!payment_value.value) return "";
  return new Intl.NumberFormat("en-US").format(Number(payment_value.value));
});

const onInput = (val) => {
  const str = (val ?? "").toString();
  let onlyNumbers = str.replace(/\D/g, ""); // إزالة أي شيء غير رقم
  let numericValue = Number(onlyNumbers);

  // لا تسمح بكتابة أكثر من المبلغ المستحق
  if (numericValue > Number(props.amount)) {
    // ترجع للقيمة السابقة بدل السماح بالتجاوز
    numericValue = Number(props.amount);
  }

  payment_value.value = numericValue ? numericValue.toString() : "";
};

// منع أي حرف غير رقم أثناء الكتابة
const allowOnlyNumbers = (event) => {
  const key = event.key;

  // السماح فقط بالأرقام
  if (!/^[0-9]$/.test(key)) {
    event.preventDefault();
    return;
  }

  // التحقق من القيمة الحالية + المفتاح الجديد
  const currentValue = payment_value.value + key;
  const numericValue = Number(currentValue);

  // منع الكتابة إذا تجاوز الحد قبل حتى إدخاله
  if (numericValue > Number(props.amount)) {
    event.preventDefault();
  }
};


function payments_value(val) {
  if (val == "all") {
    payment_value.value = props.amount;
  } else {
    payment_value.value = props.amount / 2;
  }
}

function add_payment() {
  emit("addPayment", payment_value.value);
}
</script>
<style scoped>
.card {
  border-radius: 15px !important;
  box-shadow: 0px 0px 0px 0px !important;
}

.gradient-red-card {
  background: linear-gradient(
    to right,
    rgba(239, 68, 68, 0.1),
    rgba(239, 68, 68, 0.1)
  ); /* from-green-50 to-green-100 */
  border: 1px solid rgba(252, 165, 165, 1); /* border-green-300 */
  border-radius: 0.75rem; /* rounded-xl */
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1); /* shadow-md */
  overflow: hidden; /* overflow-hidden */
}

.custom-button-1 {
  background: linear-gradient(to right, #faf5ff, #f3e8ff);
  border: 1px solid #d8b4fe;
  color: #7e22ce;
  transition: all 0.3s ease;
  border-radius: 8px;
}
.custom-button-1:hover {
  background: linear-gradient(to right, #f3e8ff, #e9d5ff);
  color: #000000;
}

.custom-button-2 {
  background: linear-gradient(to right, #eff6ff, #dbeafe);
  border: 1px solid #93c5fd;
  color: #1d4ed8;
  transition: all 0.3s ease;
  border-radius: 8px;
}
.custom-button-2:hover {
  background: linear-gradient(to right, #dbeafe, #bfdbfe);
  color: #000000;
}

.button-add-payment {
  border-radius: 8px;
  box-shadow: 0px 0px 0px 0px;
  background: linear-gradient(to bottom right, #624fc6, #5640a3);
}
</style>
