<template>
  <div class="login-page">
    <div class="login-container">
      <v-card class="login-card" elevation="0">
        <v-row no-gutters class="fill-height">
          <!-- Image Side -->
          <v-col
            cols="12" md="7"
            class="d-none d-md-flex image-side"
          >
            <v-img
              src="../assets/login.jpg"
              cover
              class="fill-height"
              gradient="to bottom, rgba(98,79,198,0.3), rgba(31,37,68,0.6)"
            >
              <div class="d-flex flex-column justify-end pa-10 fill-height">
                <h1 class="text-white mb-2" style="font-size: 2.2rem; font-weight: 800;">
                  نظام سداد
                </h1>
                <p class="text-white" style="opacity: 0.85; font-size: 1.1rem; max-width: 400px;">
                  نظام إدارة المبيعات والمخزون المتكامل
                </p>
              </div>
            </v-img>
          </v-col>

          <!-- Form Side -->
          <v-col cols="12" md="5" class="d-flex align-center">
            <div class="form-wrapper">
              <!-- Mobile Logo -->
              <div class="d-flex d-md-none align-center justify-center mb-8">
                <div class="mobile-logo">
                  <v-icon color="white" size="32">mdi-calculator-variant</v-icon>
                </div>
                <h2 class="ms-3" style="color: var(--secondary); font-weight: 800;">نظام سداد</h2>
              </div>

              <h2 class="form-title">تسجيل الدخول</h2>
              <p class="form-subtitle">أدخل بياناتك للوصول إلى النظام</p>

              <v-form ref="form" @submit.prevent="login" class="mt-8">
                <label class="input-label">البريد الإلكتروني</label>
                <v-text-field
                  v-model="email"
                  autocomplete="email"
                  type="email"
                  placeholder="example@email.com"
                  :rules="EmailRules"
                  prepend-inner-icon="mdi-email-outline"
                  class="mb-2"
                />

                <label class="input-label">كلمة المرور</label>
                <v-text-field
                  v-model="password"
                  :type="showPassword ? 'text' : 'password'"
                  placeholder="••••••••"
                  autocomplete="current-password"
                  :append-inner-icon="showPassword ? 'mdi-eye-outline' : 'mdi-eye-off-outline'"
                  @click:append-inner="showPassword = !showPassword"
                  prepend-inner-icon="mdi-lock-outline"
                  :rules="PasswordsRules"
                  class="mb-4"
                />

                <v-btn
                  type="submit"
                  :loading="loading_login"
                  color="primary"
                  size="x-large"
                  block
                  rounded="lg"
                  elevation="2"
                  class="login-btn mt-2"
                >
                  تسجيل الدخول
                  <template v-slot:loader>
                    <v-progress-circular indeterminate size="24" width="2" color="white" />
                  </template>
                </v-btn>
              </v-form>
            </div>
          </v-col>
        </v-row>
      </v-card>
    </div>
  </div>
</template>

<script setup>
import { ref, computed } from "vue";
import { useRouter } from "vue-router";
import { useUserStore } from "@/stores/user";

const email = ref(null);
const password = ref(null);
const showPassword = ref(false);
const form = ref(null);

const EmailRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 7 || "الحد الادنى لعدد الاحرف هوه 7",
  (value) => {
    const pattern =
      /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    return pattern.test(value) || "ادخلت رموز غير صحيحه";
  },
];

const PasswordsRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 8 || "الحد الادنى لعدد الاحرف هوه 8",
];

const userStore = useUserStore();
const router = useRouter();

const loading_login = computed(() => userStore.loading_login);

const login = async () => {
  const { valid } = await form.value.validate();
  if (valid) {
    try {
      await userStore.login({
        email: email.value,
        password: password.value,
      });
      router.push({ name: "home" });
    } catch (e) {
      // error handled in store
    }
  }
};
</script>

<style scoped>
.login-page {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #f5f3fa 0%, #e8e4f3 50%, #ddd7f0 100%);
  padding: 16px;
}

.login-container {
  width: 100%;
  max-width: 1000px;
}

.login-card {
  overflow: hidden;
  border: 1px solid rgba(98, 79, 198, 0.08);
  box-shadow: 0 20px 60px rgba(98, 79, 198, 0.12),
              0 4px 20px rgba(0, 0, 0, 0.04) !important;
}

.image-side {
  min-height: 560px;
}

.form-wrapper {
  width: 100%;
  padding: 48px 40px;
}

.mobile-logo {
  width: 52px;
  height: 52px;
  border-radius: 14px;
  background: linear-gradient(135deg, #624fc6, #1f2544);
  display: flex;
  align-items: center;
  justify-content: center;
}

.form-title {
  font-size: 1.7rem;
  font-weight: 800;
  color: #1a1a2e;
  margin-bottom: 6px;
}

.form-subtitle {
  color: #64607d;
  font-size: 0.95rem;
}

.input-label {
  display: block;
  font-weight: 600;
  font-size: 0.9rem;
  color: #374151;
  margin-bottom: 6px;
}

.login-btn {
  font-weight: 700;
  font-size: 1.05rem;
  letter-spacing: 0;
  text-transform: none;
}

@media (max-width: 960px) {
  .form-wrapper {
    padding: 32px 24px;
  }
  .login-card {
    border-radius: 20px !important;
  }
}

@media (max-width: 600px) {
  .login-page {
    padding: 0;
    align-items: stretch;
  }
  .login-container {
    max-width: 100%;
  }
  .login-card {
    border-radius: 0 !important;
    min-height: 100vh;
    box-shadow: none !important;
    border: none !important;
  }
  .form-wrapper {
    padding: 28px 20px;
  }
  .form-title {
    font-size: 1.4rem;
  }
  .form-subtitle {
    font-size: 0.85rem;
  }
}
</style>
