<template>
  <!-- Mobile App Bar -->
  <v-app-bar
    v-if="mobile"
    class="mobile-appbar"
    height="56"
    flat
  >
    <v-btn icon variant="text" @click="drawer = !drawer">
      <v-icon color="white" size="24">mdi-menu</v-icon>
    </v-btn>
    <v-toolbar-title class="d-flex align-center">
      <div class="brand-icon-sm me-2">
        <v-icon color="white" size="20">mdi-calculator-variant</v-icon>
      </div>
      <span class="text-white" style="font-weight: 700; font-size: 0.95rem;">نظام سداد</span>
    </v-toolbar-title>
  </v-app-bar>

  <!-- Navigation Drawer -->
  <v-navigation-drawer
    v-model="drawer"
    :rail="!mobile && rail"
    :expand-on-hover="!mobile"
    :temporary="mobile"
    app
    right
    class="sidebar"
    :width="mobile ? 260 : 280"
  >
    <!-- Logo & Brand -->
    <div class="sidebar-brand pa-4 d-flex align-center" :class="{ 'justify-center': !mobile && rail }">
      <div class="brand-icon">
        <v-icon color="white" size="32">mdi-calculator-variant</v-icon>
      </div>
      <h3 v-show="mobile || !rail" class="text-white ms-3 brand-title">نظام سداد</h3>
    </div>

    <v-divider class="mx-3" style="border-color: rgba(255,255,255,0.12);" />

    <!-- Navigation Items -->
    <v-list nav class="px-2 mt-2">
      <v-list-item
        v-for="(item, index) in navItems"
        :key="index"
        :to="item.link"
        :active="isActive(item.link)"
        class="nav-item mb-1"
        rounded="lg"
        min-height="48"
        @click="onNavClick"
      >
        <template v-slot:prepend>
          <v-icon
            :icon="item.icon"
            size="24"
            :class="isActive(item.link) ? 'text-white' : 'nav-icon'"
          />
        </template>
        <v-list-item-title class="nav-title" :class="isActive(item.link) ? 'text-white' : ''">
          {{ item.title }}
        </v-list-item-title>
      </v-list-item>
    </v-list>

    <!-- Logout Button -->
    <template v-slot:append>
      <div class="pa-3">
        <v-btn
          block
          variant="outlined"
          color="white"
          size="large"
          rounded="lg"
          class="logout-btn"
          @click="logout"
        >
          <v-icon color="white" size="22" class="me-2">mdi-logout</v-icon>
          <span v-show="mobile || !rail">تسجيل خروج</span>
        </v-btn>
      </div>
    </template>
  </v-navigation-drawer>
</template>

<script setup>
import { ref } from "vue";
import { useRoute, useRouter } from "vue-router";
import { useDisplay } from "vuetify";

const route = useRoute();
const router = useRouter();
const { mobile } = useDisplay();

const drawer = ref(!mobile.value);
const rail = ref(false);

const navItems = [
  { title: "الاحصائيات", icon: "mdi-chart-pie", link: "/statistics" },
  { title: "المنتجات", icon: "mdi-package-variant-closed", link: "/goods" },
  { title: "نقطة البيع", icon: "mdi-cart", link: "/" },
  { title: "مبيعات النقد", icon: "mdi-clipboard-text", link: "/sales" },
  { title: "مبيعات الآجل", icon: "mdi-clipboard-clock", link: "/debits" },
  { title: "التوصيل", icon: "mdi-truck-fast", link: "/sales-delivery" },
  { title: "باركود", icon: "mdi-barcode", link: "/barcode-labels" },
];

const isActive = (link) => route.path === link;

function onNavClick() {
  if (mobile.value) drawer.value = false;
}

function logout() {
  localStorage.removeItem("token");
  localStorage.removeItem("name");
  delete window.axios?.defaults?.headers?.common["Authorization"];
  router.push({ name: "login" });
}
</script>

<style scoped>
.mobile-appbar {
  background: linear-gradient(135deg, #624fc6 0%, #1f2544 100%) !important;
}
.brand-icon-sm {
  width: 32px;
  height: 32px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.sidebar {
  background: linear-gradient(180deg, #624fc6 0%, #1f2544 100%) !important;
  border: none !important;
}

.brand-icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.brand-title {
  font-weight: 800;
  letter-spacing: -0.3px;
  white-space: nowrap;
}

.nav-item {
  transition: all 0.2s ease;
  color: rgba(255, 255, 255, 0.7) !important;
}

.nav-item:hover {
  background: rgba(255, 255, 255, 0.1) !important;
  color: white !important;
}

.nav-item.v-list-item--active {
  background: rgba(255, 255, 255, 0.18) !important;
  color: white !important;
}

.nav-icon {
  color: rgba(255, 255, 255, 0.65);
}

.nav-title {
  font-weight: 600;
  font-size: 0.95rem;
  color: rgba(255, 255, 255, 0.75);
}

.logout-btn {
  border-color: rgba(255, 255, 255, 0.3) !important;
  font-weight: 700;
  transition: all 0.2s ease;
}
.logout-btn:hover {
  background: rgba(255, 255, 255, 0.1) !important;
  border-color: rgba(255, 255, 255, 0.5) !important;
}
</style>
