<template>
  <v-dialog :model-value="dialog" max-width="420" persistent>
    <v-card class="retrieve-card" rounded="xl">
      <v-toolbar class="retrieve-toolbar" height="56">
        <v-btn icon variant="text" @click="$emit('popClose')">
          <v-icon color="white" size="20">mdi-close</v-icon>
        </v-btn>
        <v-toolbar-title class="d-flex align-center justify-center">
          <v-icon color="white" class="me-2" size="20">mdi-undo-variant</v-icon>
          <span class="toolbar-title">استرجاع عناصر</span>
        </v-toolbar-title>
        <div style="width: 48px;" />
      </v-toolbar>

      <v-card-text class="pa-6">
        <div class="retrieve-hint mb-5">
          <v-icon color="primary" size="18" class="me-2">mdi-information-outline</v-icon>
          <span>حدد الكمية المراد استرجاعها <strong>(الحد الأقصى: {{ maxQuantity }})</strong></span>
        </div>

        <v-text-field
          v-model.number="quantity"
          type="number"
          label="الكمية المسترجعة"
          :rules="rules"
          :min="1"
          :max="maxQuantity"
          variant="outlined"
          color="primary"
          prepend-inner-icon="mdi-numeric"
          class="font-weight-bold"
          hide-details="auto"
        />
      </v-card-text>

      <v-card-actions class="px-6 pb-5">
        <v-btn
          variant="text"
          color="default"
          class="font-weight-bold"
          @click="$emit('popClose')"
        >
          إلغاء
        </v-btn>
        <v-spacer />
        <v-btn
          variant="flat"
          color="primary"
          class="px-8 font-weight-bold"
          rounded="lg"
          size="large"
          @click="retrieve_item"
        >
          <v-icon start size="20">mdi-undo-variant</v-icon>
          استرجاع
        </v-btn>
      </v-card-actions>
    </v-card>
  </v-dialog>
</template>

<script setup>
import { ref, defineEmits } from "vue";
import { useSnackbarStore } from "@/stores/snackbar";

const quantity = ref(1);
const emit = defineEmits(["retrieveQuantity"]);

const rules = [
  (v) => !!v || "هذا الحقل مطلوب",
  (v) => v >= 1 || "الحد الأدنى 1",
];

const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  maxQuantity: {
    type: Number,
    required: true,
  },
});

function retrieve_item() {
  if (quantity.value >= 1 && quantity.value <= props.maxQuantity) {
    emit("popClose");
    emit("retrieveQuantity", quantity.value);
  } else {
    const snackbar = useSnackbarStore();
    snackbar.showMessage({
      color: "#B71C1C",
      icon: "mdi-close-circle",
      text: "الكمية التي ادخلتها اكبر من الكمية المتوفره",
    });
  }
}
</script>

<style scoped>
.retrieve-card {
  overflow: hidden;
  border: 1px solid rgba(98, 79, 198, 0.08);
}
.retrieve-toolbar {
  background: linear-gradient(135deg, #624fc6, #4a3a9e) !important;
}
.toolbar-title {
  font-weight: 700;
  font-size: 0.95rem;
  color: white;
}
.retrieve-hint {
  display: flex;
  align-items: center;
  background: #f5f3fa;
  border: 1px solid rgba(98, 79, 198, 0.12);
  border-radius: 12px;
  padding: 10px 14px;
  font-size: 0.85rem;
  color: #3a3556;
}
</style>
