<template>
  <v-container fluid class="pa-4 pa-md-6">
    <v-row>
      <!-- Stats Cards -->
      <Card :statistics="statistics" v-if="!loading" />

      <!-- Yearly Chart -->
      <v-col cols="12" v-if="chart_data?.datasets && chart_data?.labels && !loading">
        <BarChart
          :chart_data="chart_data"
          chart-title="إحصائيات المبيعات السنوية"
        />
      </v-col>

      <!-- Date Range Filter -->
      <v-col v-if="!loading" cols="12">
        <v-card class="filter-card pa-3 pa-sm-4">
          <v-row align="center" dense>
            <v-col cols="12" sm="auto" class="d-flex align-center ga-2 mb-2 mb-sm-0">
              <v-icon color="#624fc6" size="22">mdi-calendar</v-icon>
              <span class="font-weight-bold" style="color: #1a1a2e;">فلترة حسب الفترة</span>
            </v-col>
            <v-col cols="6" sm="3" md="2">
              <v-text-field
                v-model="rangeDateFrom"
                type="date"
                label="من تاريخ"
                density="compact"
                clearable
                hide-details
              />
            </v-col>
            <v-col cols="6" sm="3" md="2">
              <v-text-field
                v-model="rangeDateTo"
                type="date"
                label="إلى تاريخ"
                density="compact"
                clearable
                hide-details
              />
            </v-col>
            <v-col cols="12" sm="auto">
              <v-btn
                color="primary"
                :loading="range_loading"
                rounded="lg"
                elevation="2"
                :block="$vuetify.display.xs"
                @click="load_range_chart"
              >
                <v-icon size="20" class="me-2">mdi-chart-bar</v-icon>
                عرض الإحصائيات
              </v-btn>
            </v-col>
          </v-row>
        </v-card>
      </v-col>

      <!-- Range Chart -->
      <v-col cols="12" v-if="range_chart_data?.datasets && range_chart_data?.labels && !loading">
        <BarChart
          :chart_data="range_chart_data"
          chart-title="إحصائيات المبيعات اليومية (حسب الفترة)"
        />
      </v-col>

      <skeletonLoader v-if="loading" />
      <CheckPassword :dialog="dialog2" @CheckPassword="dialog2 = false" />
    </v-row>
  </v-container>
</template>

<script setup>
import Card from "@/components/statistics/Card.vue";
import BarChart from "@/components/statistics/BarChart .vue";
import skeletonLoader from "@/components/statistics/skeletonLoader.vue";
import { useStatisticsStore } from "@/stores/statistics";
import CheckPassword from "@/components/layout/CheckPassword.vue";

import { computed, onMounted, ref } from "vue";
const statisticsStore = useStatisticsStore();

const statistics = computed(() => statisticsStore.statistics);
const chart_data = computed(() => statisticsStore.year_sales_sum_statistics);
const range_chart_data = computed(() => statisticsStore.range_sales_statistics);
const loading = computed(() => statisticsStore.loading);
const range_loading = computed(() => statisticsStore.range_loading);
const dialog2 = ref(true);

function pad2(n) {
  return String(n).padStart(2, "0");
}
function localYmd(d) {
  return `${d.getFullYear()}-${pad2(d.getMonth() + 1)}-${pad2(d.getDate())}`;
}
function firstDayOfMonthYmd() {
  const t = new Date();
  return `${t.getFullYear()}-${pad2(t.getMonth() + 1)}-01`;
}

const rangeDateFrom = ref(firstDayOfMonthYmd());
const rangeDateTo = ref(localYmd(new Date()));

async function load_range_chart() {
  await statisticsStore.fetch_range_sales_statistics(
    rangeDateFrom.value,
    rangeDateTo.value
  );
}

onMounted(async () => {
  await get_statistics();
  await load_range_chart();
});

function get_statistics() {
  return statisticsStore.get_statistics();
}
</script>

<style scoped>
.filter-card {
  border: 1px solid rgba(98, 79, 198, 0.06);
}
</style>

