import "@mdi/font/css/materialdesignicons.css";
import "vuetify/styles";
import { ar } from "vuetify/locale";
import { createVuetify } from "vuetify";
import { aliases, mdi } from "vuetify/iconsets/mdi";

const lightTheme = {
  dark: false,
  colors: {
    primary: "#624fc6",
    "primary-darken-1": "#4a3a9e",
    secondary: "#1f2544",
    accent: "#7c6dd8",
    success: "#16a34a",
    error: "#dc2626",
    warning: "#f59e0b",
    info: "#3b82f6",
    background: "#f5f3fa",
    surface: "#ffffff",
    "surface-variant": "#eeeaf7",
    "on-primary": "#ffffff",
    "on-secondary": "#ffffff",
    "on-surface": "#1a1a2e",
    "on-background": "#1a1a2e",
  },
};

export default createVuetify({
  icons: {
    defaultSet: "mdi",
    aliases,
    sets: { mdi },
  },
  locale: {
    locale: "ar",
    messages: { ar },
    rtl: { ar: true },
  },
  theme: {
    defaultTheme: "light",
    themes: { light: lightTheme },
  },
  defaults: {
    VBtn: {
      rounded: "lg",
      variant: "flat",
    },
    VTextField: {
      variant: "outlined",
      color: "primary",
      rounded: true,
      density: "comfortable",
      hideDetails: "auto",
    },
    VSelect: {
      variant: "outlined",
      color: "primary",
      rounded: true,
      density: "comfortable",
      hideDetails: "auto",
    },
    VCard: {
      rounded: "xl",
      elevation: 0,
    },
    VDataTableServer: {
      fixedHeader: true,
      mobileBreakpoint: 0,
    },
    VPagination: {
      rounded: "circle",
      activeColor: "primary",
      color: "surface",
      variant: "elevated",
    },
    VDialog: {
      transition: "dialog-bottom-transition",
    },
    VToolbar: {
      flat: true,
      color: "surface",
    },
    VChip: {
      rounded: "lg",
    },
    VTooltip: {
      contentClass: "custom-tooltip",
    },
  },
});
