<template>
  <v-container fluid class="pa-4 pa-md-6">
    <v-card class="pos-card" rounded="xl">
      <v-data-table-server
        :headers="headers"
        :items="goods"
        v-model:options="pagination"
        v-model:page="pagination.page"
        :items-per-page="pagination.itemsPerPage"
        :items-length="pageCount * pagination.itemsPerPage"
        :loading="loading"
        hide-default-footer
        fixed-header
        height="calc(100vh - 320px)"
        loading-text="جاري التحميل يرجى الأنتظار"
        :mobile-breakpoint="0"
      >
        <template v-slot:top>
          <div class="pa-4" style="border-bottom: 1px solid rgba(0,0,0,0.06);">
            <div class="d-flex align-center flex-wrap ga-3">
              <h3 class="page-title">
                <v-icon color="primary" class="me-2">mdi-package-variant-closed</v-icon>
                جدول البضائع
              </h3>
              <v-divider class="mx-1 d-none d-sm-block" inset vertical />

              <v-tooltip text="تحديث معلومات الجدول" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn icon variant="text" color="primary" v-bind="props" @click="reset_table">
                    <v-icon>mdi-refresh</v-icon>
                  </v-btn>
                </template>
              </v-tooltip>

              <v-tooltip text="إضافة بضائع" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn icon variant="text" color="primary" v-bind="props" @click="add_goods">
                    <v-icon>mdi-plus-box</v-icon>
                  </v-btn>
                </template>
              </v-tooltip>

              <v-spacer />

              <v-text-field
                v-model="goods_query"
                @input="query_change"
                append-inner-icon="mdi-magnify"
                label="بحث"
                class="font-weight-bold"
                clearable
                hide-details
                :style="$vuetify.display.smAndDown ? 'width: 100%;' : 'max-width: 360px; min-width: 200px;'"
              />
            </div>
          </div>
        </template>

        <template v-slot:item="{ item }">
          <tr>
            <td class="text-center font-weight-bold">{{ item.barcode }}</td>
            <td class="text-center font-weight-bold">{{ item.product.name }}</td>
            <td class="text-center">
              <v-chip
                size="default"
                :color="item.product.type == 0 ? 'primary' : 'info'"
                variant="tonal"
              >
                {{ item.product.type == 0 ? 'ملابس' : 'حذاء' }}
              </v-chip>
            </td>
            <td class="text-center font-weight-bold">{{ item.model ?? "لايوجد" }}</td>
            <td class="text-center">
              <v-swatches v-model="item.color" :disabled="true" />
            </td>

            <!-- Size + Quantity combined -->
            <td class="text-center">
              <div class="size-grid">
                <div
                  v-for="(subItem, subIdx) in sortedItems(item.items)"
                  :key="subIdx"
                  :class="[
                    'size-chip',
                    subItem.quantity == 0 ? 'size-chip--out' : '',
                  ]"
                >
                  <span class="size-chip__label">{{ subItem.size }}</span>
                  <span class="size-chip__qty">{{ subItem.quantity }}</span>
                </div>
              </div>
            </td>

            <td class="text-center font-weight-bold">
              {{ $filters.formatNumber(item.purchase_price) }}
            </td>
            <td class="text-center font-weight-bold">
              {{ $filters.formatNumber(item.selling_price) }}
            </td>
            <td class="text-center font-weight-bold">
              {{ $moment(item.created_at).format("YYYY-MM-DD") }}
            </td>
            <td class="text-center">
              <v-tooltip text="حذف" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn
                    icon variant="text" color="error" size="small"
                    v-bind="props"
                    @click="pop_delete_product(item.product.id)"
                    :loading="delete_loading && id_delete_product === item.product.id"
                  >
                    <v-icon>mdi-delete</v-icon>
                    <template v-slot:loader>
                      <span class="custom-loader"><v-icon color="error">mdi-cached</v-icon></span>
                    </template>
                  </v-btn>
                </template>
              </v-tooltip>
              <v-tooltip text="تعديل" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn
                    icon variant="text" color="secondary" size="small"
                    v-bind="props"
                    @click="pop_edit_product(item)"
                  >
                    <v-icon>mdi-pencil</v-icon>
                  </v-btn>
                </template>
              </v-tooltip>
            </td>
          </tr>
        </template>
      </v-data-table-server>

      <!-- Pagination -->
      <div class="text-center py-3 py-sm-4 px-3 px-sm-4">
        <v-row align="center" dense>
          <v-col cols="12" sm="7">
            <v-pagination
              v-model="pagination.page"
              :length="pageCount"
              :total-visible="$vuetify.display.xs ? 3 : 5"
              density="comfortable"
            />
          </v-col>
          <v-col cols="12" sm="5">
            <v-select
              v-model="pagination.itemsPerPage"
              :items="items"
              label="عدد العناصر"
              class="font-weight-bold"
              persistent-hint
              hide-details="auto"
            />
          </v-col>
        </v-row>
      </div>
    </v-card>

    <PopAddGoods :dialog="dialog" @popClose="dialog = false" />
    <PopDeleteItems
      :dialog="dialog_delete"
      @popClose="dialog_delete = false"
      :title="title"
      @deletePorduct="delete_porduct"
    />
    <PopEditGoods
      :dialog="dialog_edit"
      @popClose="dialog_edit = false"
      :item="item_edit_product"
    />
  </v-container>
</template>

<script setup>
import { ref, computed, watch } from "vue";
import { useDisplay } from "vuetify";
import { useGoodsStore } from "@/stores/goods";

const { smAndDown } = useDisplay();
import PopAddGoods from "@/components/goods/PopAddGoods.vue";
import PopDeleteItems from "@/components/layout/PopDeleteItems.vue";
import PopEditGoods from "@/components/goods/PopEditGoods.vue";

const goodsStore = useGoodsStore();

const items = [5, 10, 15, 20, 25, 50, 100, 200];
const pagination = ref({ page: 1, itemsPerPage: 10, sortBy: [], sortDesc: [] });

const dialog = ref(false);
const dialog_delete = ref(false);
const id_delete_product = ref(null);
const dialog_edit = ref(false);
const item_edit_product = ref(null);

const title = ref("حذف المنتج");

const headers = computed(() => {
  const isMobile = smAndDown.value;
  return [
    { title: "باركود", value: "barcode", align: "center", width: isMobile ? "100px" : "150px" },
    { title: "المنتج", value: "name", align: "center", width: isMobile ? "90px" : "150px" },
    { title: "نوع", value: "type", align: "center", width: isMobile ? "70px" : "100px" },
    { title: "موديل", value: "model", align: "center", width: isMobile ? "70px" : "120px" },
    { title: "اللون", value: "color", align: "center", width: isMobile ? "60px" : "90px" },
    { title: "القياس", value: "size", align: "center", width: isMobile ? "120px" : "200px" },
    { title: "الشراء", value: "purchase_price", align: "center", width: isMobile ? "80px" : "140px" },
    { title: "البيع", value: "selling_price", align: "center", width: isMobile ? "80px" : "140px" },
    { title: "التاريخ", value: "created_at", align: "center", width: isMobile ? "90px" : "130px" },
    { title: "عمليات", value: "operations", align: "center", width: isMobile ? "80px" : "120px" },
  ];
});

const goods_query = computed({
  get: () => goodsStore.goods_query,
  set: (val) => (goodsStore.goods_query = val),
});

const pageCount = computed(() => goodsStore.pageCount);
const goods = computed(() => goodsStore.goods);
const loading = computed(() => goodsStore.table_loading);
const delete_loading = computed(() => goodsStore.delete_product_loading);

const params = computed({
  get: () => goodsStore.params,
  set: (val) => (goodsStore.params = val),
});

function get_goods() {
  const par = { ...pagination.value };
  params.value = par;
  goodsStore.get_goods();
}

const sizeOrder = { 'XXS': 1, 'XS': 2, 'S': 3, 'M': 4, 'L': 5, 'XL': 6, 'XXL': 7, 'XXXL': 8, '2XL': 7, '3XL': 8, '4XL': 9, '5XL': 10 };

function sizeRank(size) {
  const s = String(size).trim().toUpperCase();
  if (sizeOrder[s] !== undefined) return sizeOrder[s];
  const n = parseFloat(s);
  if (!isNaN(n)) return 100 + n;
  return 999;
}

function sortedItems(items) {
  return [...items].sort((a, b) => sizeRank(a.size) - sizeRank(b.size));
}

function pop_edit_product(item) {
  dialog_edit.value = true;
  item_edit_product.value = item;
}

function pop_delete_product(id) {
  dialog_delete.value = true;
  id_delete_product.value = id;
}

const delete_porduct = async () => {
  dialog_delete.value = false;
  let data = { id: id_delete_product.value };
  try {
    await goodsStore.delete_porduct(data);
    id_delete_product.value = null;
  } catch (e) {
    // error handled in store
  }
};

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_goods();
    pagination.value.page = 1;
  }, 300);
}

function reset_table() {
  goodsStore.reset_table();
  get_goods();
}

function add_goods() {
  dialog.value = true;
}

watch(pagination, () => { get_goods(); }, { deep: true });

watch(goods_query, (newVal) => {
  if (newVal === null || newVal === "") {
    pagination.value.page = 1;
    get_goods();
  }
});
</script>

<style scoped>
.pos-card {
  border: 1px solid rgba(98, 79, 198, 0.06);
  overflow: hidden;
}
.page-title {
  font-weight: 800;
  color: #1a1a2e;
  white-space: nowrap;
  display: flex;
  align-items: center;
}

.size-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  justify-content: center;
  padding: 4px 0;
}
.size-chip {
  display: flex;
  flex-direction: column;
  align-items: center;
  min-width: 52px;
  padding: 6px 10px 5px;
  border: 1.5px solid rgba(98, 79, 198, 0.25);
  border-radius: 10px;
  background: #faf9fe;
  transition: all 0.15s ease;
}
.size-chip:hover:not(.size-chip--out) {
  border-color: #624fc6;
  background: #eee9ff;
  transform: translateY(-1px);
  box-shadow: 0 2px 8px rgba(98, 79, 198, 0.18);
}
.size-chip--out {
  opacity: 0.4;
  background: #f5f5f5;
  border-color: rgba(0,0,0,0.08);
}
.size-chip__label {
  font-size: 0.88rem;
  font-weight: 800;
  color: #1a1a2e;
  line-height: 1.3;
}
.size-chip__qty {
  font-size: 0.7rem;
  font-weight: 600;
  color: #64607d;
  line-height: 1;
}
</style>
