<template>
  <v-container fluid class="pa-4 pa-md-6">
    <v-row>
      <v-col cols="12">
        <v-card class="pos-card">
          <!-- Toolbar -->
          <div class="pos-toolbar pa-4">
            <div class="d-flex align-center flex-wrap ga-3">
              <h3 class="page-title">
                <v-icon color="primary" class="me-2">mdi-cart</v-icon>
                نقطة البيع
              </h3>

              <v-divider vertical class="mx-1 d-none d-sm-block" />

              <v-tooltip text="تحديث" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn icon variant="text" color="primary" v-bind="props" @click="reset_table">
                    <v-icon>mdi-refresh</v-icon>
                  </v-btn>
                </template>
              </v-tooltip>

              <v-tooltip text="إضافة فاتورة" location="bottom">
                <template v-slot:activator="{ props }">
                  <v-btn
                    icon variant="text" color="primary" v-bind="props"
                    @click="add_sales"
                    :loading="loading_sale"
                  >
                    <v-icon>mdi-book-plus</v-icon>
                    <template v-slot:loader>
                      <span class="custom-loader"><v-icon color="primary">mdi-cached</v-icon></span>
                    </template>
                  </v-btn>
                </template>
              </v-tooltip>

              <v-spacer />

              <v-text-field
                ref="barcodeInput"
                v-model="barcode_query"
                @input="query_change"
                append-inner-icon="mdi-magnify"
                label="مسح الباركود أو بحث"
                class="barcode-input"
                :style="$vuetify.display.smAndDown ? 'width: 100%; max-width: 100%;' : 'max-width: 360px; min-width: 200px;'"
                clearable
                hide-details
              />
            </div>
          </div>

          <!-- Table -->
          <v-data-table-server
            :headers="headers"
            :items="products"
            :loading="loading"
            hide-default-footer
            :height="$vuetify.display.smAndDown ? 'calc(100vh - 300px)' : 'calc(100vh - 360px)'"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:item="{ item, index }">
              <tr>
                <td class="text-center font-weight-bold">{{ item.barcode }}</td>
                <td class="text-center font-weight-bold">{{ item.product.name }}</td>
                <td class="text-center">
                  <v-chip
                    size="default"
                    :color="item.product.type == 0 ? 'primary' : 'info'"
                    variant="tonal"
                  >
                    {{ item.product.type == 0 ? 'ملابس' : item.product.type == 1 ? 'حذاء' : 'أخرى' }}
                  </v-chip>
                </td>

                <!-- Model -->
                <td class="text-center font-weight-bold">
                  {{ item.model ?? "—" }}
                </td>

                <td class="text-center">
                  <v-swatches v-model="item.color" :disabled="true" />
                </td>

                <!-- Sizes -->
                <td class="text-center">
                  <div class="size-grid">
                    <button
                      v-for="(subItem, subIndex) in sortedItems(item.items)"
                      :key="subIndex"
                      :disabled="subItem.status == 'sold_out' || subItem.quantity == 0 || isSizeSelectedElsewhere(subItem.id, index)"
                      :class="[
                        'size-chip',
                        selectedItemPerRow[`${index}`]?.id === subItem.id ? 'size-chip--active' : '',
                        subItem.quantity == 0 ? 'size-chip--out' : '',
                      ]"
                      @click="selectSize(index, item, subItem)"
                    >
                      <span class="size-chip__label">{{ subItem.size }}</span>
                      <span class="size-chip__qty">{{ subItem.quantity }}</span>
                    </button>
                  </div>
                </td>

                <!-- Quantity -->
                <td class="text-center">
                  <div v-if="selectedItemPerRow[`${index}`]" class="d-flex align-center justify-center">
                    <v-btn
                      size="small" icon variant="tonal" color="secondary"
                      @click="changeQuantity(index, item, 'dec')"
                    >
                      <v-icon size="18">mdi-minus</v-icon>
                    </v-btn>
                    <span class="mx-3 font-weight-bold text-h6">
                      {{ selectedItemPerRow[`${index}`].quantity }}
                    </span>
                    <v-btn
                      size="small" icon variant="tonal" color="secondary"
                      @click="changeQuantity(index, item, 'inc')"
                    >
                      <v-icon size="18">mdi-plus</v-icon>
                    </v-btn>
                  </div>
                  <span v-else class="text-medium-emphasis text-body-2">اختر القياس</span>
                </td>

                <!-- Available Qty -->
                <td class="text-center">
                  <v-chip v-if="selectedItemPerRow[`${index}`]" size="default" color="success" variant="tonal">
                    {{ getSelectedItemQuantity(index, item) }}
                  </v-chip>
                  <span v-else class="text-medium-emphasis text-body-2">—</span>
                </td>

                <!-- Price / Discount -->
                <td class="text-center">
                  <div v-if="selectedItemPerRow[`${index}`]" style="min-width: 180px;">
                    <Selects
                      :items="discountOptionsFor(item.selling_price)"
                      itemValue="value"
                      itemText="type"
                      :clearable="false"
                      :model-value="selectedItemPerRow[`${index}`]?.discount ?? 0"
                      v-on:update-value="(val) => setDiscountOption(index, val, item.selling_price)"
                      class="selects-class"
                    />
                  </div>
                  <span v-else class="font-weight-bold">{{ formatNumber(item.selling_price) }} د.ع</span>
                </td>

                <!-- Delete -->
                <td class="text-center">
                  <v-btn icon variant="text" color="error" size="default" @click="pop_delete_product(index)">
                    <v-icon>mdi-delete</v-icon>
                  </v-btn>
                </td>
              </tr>
            </template>
          </v-data-table-server>

          <!-- Footer: Sale Type + Total -->
          <v-divider />
          <div class="pos-footer pa-3 pa-sm-4">
            <v-row align="center" dense>
              <v-col cols="6" sm="4" md="3">
                <Selects
                  v-on:update-value="(val) => { sale_type = val; focusBarcode(); }"
                  v-model="sale_type"
                  label="نوع الشراء"
                  itemValue="value"
                  itemText="type"
                  :items="sale_types"
                  class="selects-class"
                />
              </v-col>
              <v-spacer />
              <v-col cols="6" sm="auto" class="d-flex align-center justify-end">
                <div class="total-display">
                  <span class="total-label">المجموع الكلي</span>
                  <span class="total-amount">{{ formatNumber(totalPrice) }} <small>د.ع</small></span>
                </div>
              </v-col>
            </v-row>
          </div>
        </v-card>
      </v-col>

      <PopSalesDebit
        :dialog="dialog"
        :totalPrice="totalPrice"
        @popClose="dialog = false"
        @addSales="addSales"
      />
      <PopAddSalesDelivery
        :dialog="dialog2"
        :totalPrice="totalPrice"
        @popClose="dialog2 = false"
        @addSales="addSales"
      />
    </v-row>
  </v-container>
</template>

<script setup>
import {
  ref,
  computed,
  onMounted,
  onBeforeUnmount,
  nextTick,
  h,
  render,
} from "vue";

import { useGoodsStore } from "@/stores/goods";
import { useSalesStore } from "@/stores/sales";
import { useDisplay } from "vuetify";
import InvoiceReceipt from "@/components/layout/invoice.vue";
import PopSalesDebit from "@/components/sales/PopSalesDebit.vue";
import PopAddSalesDelivery from "@/components/sales/PopAddSalesDelivery.vue";
import Selects from "@/components/layout/Selects.vue";

const goodsStore = useGoodsStore();
const salesStore = useSalesStore();
const { smAndDown } = useDisplay();

const selectedItemPerRow = ref({});
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");
const sale_type = ref({ type: "نقد", value: 0 });
const sale_types = [
  { type: "نقد", value: 0 },
  { type: "آجل", value: 1 },
  { type: "توصيل", value: 2 },
];
const barcodeInput = ref(null);
const dialog = ref(false);
const dialog2 = ref(false);

const headers = computed(() => {
  const m = smAndDown.value;
  return [
    { title: "باركود", value: "barcode", align: "center", width: m ? "90px" : "140px" },
    { title: "المنتج", value: "name", align: "center", width: m ? "80px" : "140px" },
    { title: "نوع", value: "type", align: "center", width: m ? "60px" : "90px" },
    { title: "موديل", value: "model", align: "center", width: m ? "60px" : "100px" },
    { title: "اللون", value: "color", align: "center", width: m ? "55px" : "80px" },
    { title: "القياس", value: "size", align: "center", width: m ? "110px" : "180px" },
    { title: "الكمية", value: "quantity", align: "center", width: m ? "90px" : "130px" },
    { title: "المتوفر", value: "available", align: "center", width: m ? "60px" : "90px" },
    { title: "السعر", value: "selling_price", align: "center", width: m ? "120px" : "200px" },
    { title: "حذف", value: "operations", align: "center", width: m ? "50px" : "70px" },
  ];
});

const barcode_query = computed({
  get: () => goodsStore.barcode_query,
  set: (val) => (goodsStore.barcode_query = val),
});

const products = computed(() => goodsStore.temp_products);
const loading = computed(() => goodsStore.table_temp_product_loading);
const loading_sale = computed(() => salesStore.loading);

const formatNumber = (n) => {
  if (n == null || n === undefined) return 0;
  return new Intl.NumberFormat().format(Number(n));
};

const toNumber = (v) => {
  if (v === null || v === undefined) return 0;
  if (typeof v === "number" && Number.isFinite(v)) return v;
  const s = String(v).replace(/[,،\s]/g, "");
  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
};

const discountValues = [
  25000, 15000, 10000, 5000, 0, -5000, -10000, -15000, -25000,
];

onMounted(() => {
  focusBarcode();
  document.addEventListener("click", handleClickOutside);
});
onBeforeUnmount(() => {
  document.removeEventListener("click", handleClickOutside);
});

function handleClickOutside(e) {
  const inputEl = barcodeInput.value?.$el;
  if (inputEl && inputEl.contains(e.target)) return;
  if (e.target.closest(".v-overlay") || e.target.closest(".selects-class")) return;
  focusBarcode();
}

function get_products_by_barcode() {
  if (barcode_query.value && barcode_query.value.length > 0 && barcode_query.value !== "") {
    goodsStore.get_products_by_barcode();
    barcode_query.value = null;
    focusBarcode();
  }
}

function focusBarcode() {
  nextTick(() => { barcodeInput.value?.focus(); });
}

function discountOptionsFor(price) {
  const p = Number(price ?? 0);
  return discountValues.map((d) => {
    const finalP = Math.max(0, p + d);
    if (d > 0) return { type: `${formatNumber(finalP)} د.ع - زيادة ${formatNumber(d)} د.ع`, value: d };
    else if (d === 0) return { type: `${formatNumber(p)} د.ع (بدون تغيير)`, value: d };
    else return { type: `${formatNumber(finalP)} د.ع – خصم ${formatNumber(Math.abs(d))} د.ع`, value: d };
  });
}

function selectSize(index, item, subItem) {
  selectedItemPerRow.value[index] = {
    id: subItem.id,
    name: item.product.name,
    size: subItem.size,
    price: toNumber(item.selling_price),
    dozen_id: subItem.dozen_id,
    quantity: 1,
    discount: 0,
    final_price: toNumber(item.selling_price),
  };
  focusBarcode();
}

function setDiscountOption(index, discountValue, basePrice) {
  if (!selectedItemPerRow.value[index]) return;
  let discountNum = 0;
  if (discountValue !== null && typeof discountValue === "object") {
    discountNum = toNumber(discountValue.value ?? discountValue);
  } else {
    discountNum = toNumber(discountValue);
  }
  const base = toNumber(basePrice ?? selectedItemPerRow.value[index].price ?? 0);
  const finalP = Math.max(0, base + discountNum);
  selectedItemPerRow.value[index].discount = discountNum;
  selectedItemPerRow.value[index].final_price = finalP;
  focusBarcode();
}

const totalPrice = computed(() => {
  let total = 0;
  Object.entries(selectedItemPerRow.value).forEach(([key, selected]) => {
    const index = parseInt(key);
    const product = products.value[index];
    if (product && selected) {
      const unit = toNumber(selected.final_price ?? product.selling_price ?? selected.price ?? 0);
      const qty = toNumber(selected.quantity ?? 0);
      total += qty * unit;
    }
  });
  return total;
});

function changeQuantity(index, row, type) {
  const selected = selectedItemPerRow.value[index];
  if (!selected) return;
  const selectedItem = row.items.find((i) => i.id === selected.id);
  if (!selectedItem) return;
  if (type === "inc") {
    if (selected.quantity < selectedItem.quantity) selected.quantity++;
  } else if (type === "dec" && selected.quantity > 1) {
    selected.quantity--;
  }
  nextTick(() => focusBarcode());
}

function getSelectedItemQuantity(index, row) {
  const selected = selectedItemPerRow.value[index];
  if (!selected) return 0;
  const selectedItem = row.items.find((i) => i.id === selected.id);
  return selectedItem ? selectedItem.quantity : 0;
}

const sizeOrder = { 'XXS': 1, 'XS': 2, 'S': 3, 'M': 4, 'L': 5, 'XL': 6, 'XXL': 7, 'XXXL': 8, '2XL': 7, '3XL': 8, '4XL': 9, '5XL': 10 };

function sizeRank(size) {
  const s = String(size).trim().toUpperCase();
  if (sizeOrder[s] !== undefined) return sizeOrder[s];
  const n = parseFloat(s);
  if (!isNaN(n)) return 100 + n;
  return 999;
}

function sortedItems(items) {
  return [...items].sort((a, b) => sizeRank(a.size) - sizeRank(b.size));
}

function isSizeSelectedElsewhere(subItemId, currentRowIndex) {
  return Object.entries(selectedItemPerRow.value).some(([key, val]) => {
    return key !== currentRowIndex.toString() && val.id === subItemId;
  });
}

function pop_delete_product(index) {
  if (index >= 0 && index < products.value.length) {
    products.value.splice(index, 1);
    if (selectedItemPerRow.value[index]) delete selectedItemPerRow.value[index];
    const newSelected = {};
    Object.entries(selectedItemPerRow.value).forEach(([key, val]) => {
      const keyNum = parseInt(key);
      if (keyNum < index) newSelected[key] = val;
      else if (keyNum > index) newSelected[keyNum - 1] = val;
    });
    selectedItemPerRow.value = newSelected;
    focusBarcode();
  }
}

let timerId = null;
function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => { get_products_by_barcode(); }, 200);
}

function reset_table() {
  goodsStore.temp_products = [];
  goodsStore.barcode_query = null;
  selectedItemPerRow.value = {};
  focusBarcode();
}

let isPrinting = false;
function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;
  const container = document.createElement("div");
  container.id = "print-root";
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);
  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };
  const vnode = h(InvoiceReceipt, {
    purchasedItems: items.sale_items,
    nameStore: nameStore.value,
    paperSize: paperSize.value,
    saleType: sale_type.value.value,
    invoiceId: items.invoice_number,
    date: items.created_at,
    name: items.debtor_user?.name ?? "",
    phone: items.debtor_user?.phone ?? "",
    city: items.debtor_user?.city ?? "",
    remaining_amount: items.debtor_user?.remaining_amount ?? "",
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print();
      });
    },
  });
  render(vnode, container);
}

async function add_sales() {
  if (sale_type.value.value == 1) dialog.value = true;
  else if (sale_type.value.value == 2) dialog2.value = true;
  else addSales(null);
}

async function addSales(info_user) {
  if (Object.keys(selectedItemPerRow.value).length > 0) {
    let data = {};
    const variantsArray = Object.entries(selectedItemPerRow.value).map(
      ([, sel]) => ({
        id: sel.id,
        dozen_id: sel.dozen_id,
        product_name: sel.name,
        size: sel.size,
        price: Number(sel.price),
        quantity: Number(sel.quantity),
        discount_amount: Number(sel.discount ?? 0),
        final_price: Number(sel.final_price ?? sel.price),
      })
    );
    data["variants"] = variantsArray;
    data["sale_type"] = sale_type.value.value;
    if (info_user != null && info_user["user_type"] == 1) {
      data["debtor_id"] = info_user["debtor_id"];
      data["payment_amount"] = info_user["payment_amount"];
    }
    if (info_user != null && info_user["user_type"] == 2) {
      data["name"] = info_user["name"];
      data["city"] = info_user["city"];
      data["phone"] = info_user["phone"];
    }
    try {
      const response = await salesStore.add_sales(data);
      const sales = response.data.result[0];
      printInvoice(sales);
      reset_table();
      focusBarcode();
    } catch (error) {
      console.error("حدث خطأ أثناء إضافة المبيعات:", error);
    }
  }
}
</script>

<style scoped>
.pos-card {
  border: 1px solid rgba(98, 79, 198, 0.06);
  overflow: hidden;
}

.pos-toolbar {
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
}

.page-title {
  font-weight: 800;
  color: #1a1a2e;
  white-space: nowrap;
}

.barcode-input :deep(.v-field) {
  background: #f5f3fa;
}

.size-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  justify-content: center;
  padding: 4px 0;
}

.size-chip {
  display: flex;
  flex-direction: column;
  align-items: center;
  min-width: 52px;
  padding: 6px 10px 5px;
  border: 1.5px solid rgba(98, 79, 198, 0.25);
  border-radius: 10px;
  background: #faf9fe;
  cursor: pointer;
  transition: all 0.15s ease;
  outline: none;
}
.size-chip:hover:not(:disabled) {
  border-color: #624fc6;
  background: #f0ecfa;
  transform: translateY(-1px);
  box-shadow: 0 2px 8px rgba(98, 79, 198, 0.15);
}
.size-chip--active {
  background: linear-gradient(135deg, #624fc6, #4a3a9e) !important;
  border-color: #624fc6 !important;
  box-shadow: 0 3px 10px rgba(98, 79, 198, 0.3);
}
.size-chip--active .size-chip__label,
.size-chip--active .size-chip__qty {
  color: #fff !important;
}
.size-chip--out,
.size-chip:disabled {
  opacity: 0.35;
  cursor: not-allowed;
  background: #f3f3f3;
  border-color: #e0e0e0;
}
.size-chip__label {
  font-size: 0.88rem;
  font-weight: 800;
  color: #1a1a2e;
  line-height: 1.3;
}
.size-chip__qty {
  font-size: 0.7rem;
  font-weight: 600;
  color: #64607d;
  line-height: 1;
}

.pos-footer {
  background: #faf9fe;
}

.total-display {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  padding: 12px 20px;
  background: linear-gradient(135deg, #624fc6, #4a3a9e);
  border-radius: 16px;
  min-width: 200px;
}
.total-label {
  font-size: 0.8rem;
  color: rgba(255, 255, 255, 0.8);
  font-weight: 600;
}
.total-amount {
  font-size: 1.5rem;
  font-weight: 800;
  color: white;
  line-height: 1.2;
}
.total-amount small {
  font-size: 0.75rem;
  font-weight: 600;
}

@media (max-width: 960px) {
  .page-title {
    font-size: 0.95rem;
  }
  .total-display {
    min-width: auto;
    padding: 8px 14px;
    border-radius: 12px;
  }
  .total-amount {
    font-size: 1.15rem;
  }
  .size-chip {
    min-width: 42px;
    padding: 4px 6px 3px;
  }
  .size-chip__label {
    font-size: 0.78rem;
  }
  .size-chip__qty {
    font-size: 0.62rem;
  }
}

@media (max-width: 600px) {
  .total-display {
    min-width: auto;
    padding: 6px 10px;
    border-radius: 10px;
  }
  .total-label {
    font-size: 0.68rem;
  }
  .total-amount {
    font-size: 1rem;
  }
}
</style>
