import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";
export const useDebitsStore = defineStore("debits", {
  state: () => ({
    debtor_users: [],
    debtor_user_add: [],

    query: "",
    query2: "",

    pageCount: 1,
    params: {
      sortBy: [],
      sortDesc: [],
      page: 1,
      itemsPerPage: 1,
    },
    table_loading: false,
    loading: false,
    loading_add_user: false,
    loading_update_user: false,

    loading_change: false,

    date_from: null,
    date_to: null,

    // get_sales_to_debtor
    statistics_debtor_user: [],
    loading_statistics_debtor: false,

    sales_debtor: [],
    payment_status: null,
    debtor_query: "",
    debtor_state: "done",
    loading_debtor: false,
    params_debtor: {
      sortBy: [],
      sortDesc: [],
      page: 1,
      itemsPerPage: 10,
    },
    id: null,

    // get_sales_to_debtor_with_payments_items
    sale_id: null,
    loading_sales_debtor_with_payment_items: false,
    loading_add_payment: false,
    loading_add_payment2: false,
    info_all_sale: null,
    retrieve_loading: false,

    // data_invoice
    data_invoice: null,
    loading_data_invoice: false,

    loading_change_debit_type: false,
  }),

  actions: {
    async reset_table() {
      this.params.page = 1;
      this.params.sortBy = [];
      this.params.sortDesc = [];
      this.query = "";
      this.pageCount = 1;
      this.table_loading = false;
      this.status = null;
      this.debtor_users = [];
    },

    async get_debtor_users_with_sales_and_payment_dates() {
      const data = this.params;
      this.table_loading = true;
      try {
        const skip = (data.page - 1) * data.itemsPerPage;
        const limit = data.itemsPerPage;

        let query = "";
        if (this.query && this.query.length > 0) {
          query = `&query=${this.query}`;
        }

        const response = await axios.get(
          `${server}/api/get_debtor_users?skip=${skip}&limit=${limit}${query}`
        );

        this.pageCount = response.data.count;
        this.debtor_users = response.data.result;
        this.table_loading = false;

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },
    async get_debtor_users() {
      this.table_loading = true;
      try {
        let query = "";
        if (this.query2 && this.query2.length > 0) {
          query = `${this.query2}`;
        }

        const response = await axios.get(
          `${server}/api/get_debtor_users?query=${query}`
        );

        this.debtor_user_add = response.data.result;
        this.table_loading = false;

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async get_invoice_to_print(data) {
      const snackbar = useSnackbarStore();

      this.loading_data_invoice = true;
      try {
        const response = await axios.post(
          `${server}/api/get_invoice_to_print`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        this.data_invoice = response.data.result[0];

        this.loading_data_invoice = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_data_invoice = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async add_debtor_users(data) {
      const snackbar = useSnackbarStore();

      this.loading_add_user = true;
      try {
        const response = await axios.post(
          `${server}/api/add_debtor_users`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        this.debtor_users.unshift(response.data.result[0]);

        this.loading_add_user = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_add_user = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },
    async update_debtor_users(data) {
      const snackbar = useSnackbarStore();

      this.loading_update_user = true;
      try {
        const response = await axios.post(
          `${server}/api/edit_debtor_users`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        let index = this.debtor_users.findIndex((e) => e.id == data.id);
        if (index !== -1) {
          this.debtor_users.splice(index, 1, response.data.result[0]);
        }

        this.debtor_users[index] = response.data.result[0];

        this.loading_update_user = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_update_user = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async get_sales_to_debtor() {
      if (this.loading_debtor || this.debtor_state === "finished") return;
      this.loading_debtor = true;
      const data_ = this.params_debtor;

      try {
        const skip = (data_.page - 1) * data_.itemsPerPage;
        const limit = data_.itemsPerPage;

        let query = "";
        if (this.debtor_query && this.debtor_query.length > 0) {
          query = `&query=${this.debtor_query}`;
        }

        let id = "";
        if (this.id && this.id.length > 0) {
          id = `&id=${this.id}`;
        }
        let statusParam = "";
        if (
          this.payment_status != null &&
          this.payment_status != "" &&
          this.payment_status != undefined
        ) {
          statusParam = `&payment_status=${this.payment_status}`;
        }

        const response = await axios.get(
          `${server}/api/get_sales_to_debtor?skip=${skip}&limit=${limit}${id}${statusParam}${query}`
        );

        this.loading_debtor = false;

        const data = response?.data?.result ?? response?.data?.data ?? [];

        if (!Array.isArray(data) || data.length === 0) {
          // لا مزيد من البيانات
          this.debtor_state = "finished";
          // لا نزيد الصفحة لأننا لم نحصل على عناصر
          return;
        }

        this.params_debtor.page += 1;
        const newItems = data.filter(
          (d) => !this.sales_debtor.some((t) => t.id === d.id)
        );
        this.sales_debtor.push(...newItems);
        this.debtor_state = "done";

        return response;
      } catch (error) {
        this.table_loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },
    async get_statistics_debtor_user() {
      this.loading_statistics_debtor = true;
      try {
        let id = "";
        if (this.id && this.id.length > 0) {
          id = `?id=${this.id}`;
        }

        const response = await axios.get(
          `${server}/api/get_statistics_debtor_user${id}`
        );

        this.loading_statistics_debtor = false;

        this.statistics_debtor_user = response.data.result;

        return response;
      } catch (error) {
        this.loading_statistics_debtor = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async get_sales_to_debtor_with_payments_items() {
      this.loading_sales_debtor_with_payment_items = true;
      try {
        let id = "";
        if (this.sale_id && this.sale_id.length > 0) {
          id = `?id=${this.sale_id}`;
        }

        const response = await axios.get(
          `${server}/api/get_sales_to_debtor_with_payments_items${id}`
        );

        this.loading_sales_debtor_with_payment_items = false;

        this.info_all_sale = response.data.result[0];

        return response;
      } catch (error) {
        this.loading_sales_debtor_with_payment_items = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async add_new_payment(data) {
      const snackbar = useSnackbarStore();

      this.loading_add_payment = true;
      try {
        const response = await axios.post(
          `${server}/api/add_new_payment`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        this.info_all_sale = response.data.result[0];

        // تحديث الإحصائيات العامة للمدين (debt overview)
        this.statistics_debtor_user = {
          ...this.statistics_debtor_user,
          debtorUser: {
            ...this.statistics_debtor_user.debtorUser,
            remaining_amount: this.info_all_sale.debtor_user.remaining_amount,
          },
        };

        // تحديث الفاتورة نفسها داخل المصفوفة sales_debtor
        const index = this.sales_debtor.findIndex(
          (e) => e.id === this.info_all_sale.id
        );

        if (index !== -1) {
          const updatedSale = {
            ...this.sales_debtor[index],
            payment_dates: {
              ...this.sales_debtor[index].payment_dates,
              amount_paid: this.info_all_sale.payment_dates.amount_paid,
              remaining_amount:
                this.info_all_sale.payment_dates.remaining_amount,
            },
            total: this.info_all_sale.total,
            payment_status: this.info_all_sale.payment_status,
          };

          // نحدث المصفوفة لضمان reactivity
          this.sales_debtor.splice(index, 1, updatedSale);
        }

        this.loading_add_payment = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_add_payment = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async retrieve_item_debtor(data) {
      const snackbar = useSnackbarStore();

      this.retrieve_loading = true;
      try {
        const response = await axios.post(
          `${server}/api/retrieve_item_debtor`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        const saleData = response.data.result.sale;
        const debtorRemaining = response.data.result.debtor_user_remaining;

        this.info_all_sale = saleData;

        this.statistics_debtor_user = {
          ...this.statistics_debtor_user,
          debtorUser: {
            ...this.statistics_debtor_user.debtorUser,
            remaining_amount: debtorRemaining,
          },
        };

        const index = this.sales_debtor.findIndex(
          (e) => e.id === this.info_all_sale.id
        );
        if (index !== -1) {
          const updatedSale = {
            ...this.sales_debtor[index],
            payment_dates: {
              ...this.sales_debtor[index].payment_dates,
              amount_paid: this.info_all_sale.payment_dates.amount_paid,
              remaining_amount:
                this.info_all_sale.payment_dates.remaining_amount,
            },
            payment_status: this.info_all_sale.payment_status,
            total: this.info_all_sale.total,
            partial_return: this.info_all_sale.partial_return,
            retrieve: this.info_all_sale.retrieve,
          };

          // استخدم $patch حتى تضمن reactivity
          this.sales_debtor.splice(index, 1, updatedSale);
        }
        this.retrieve_loading = false;

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.retrieve_loading = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async add_payment(data) {
      const snackbar = useSnackbarStore();

      this.loading_add_payment2 = true;
      try {
        const response = await axios.post(`${server}/api/add_payment`, data, {
          headers: {
            "Content-Type": "application/json",
          },
          method: "POST",
        });

        return response;
      } catch (error) {
        this.loading_add_payment2 = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },

    async change_debit_type(data) {
      const snackbar = useSnackbarStore();

      this.loading_change_debit_type = true;
      try {
        const response = await axios.post(
          `${server}/api/change_debit_type`,
          data,
          {
            headers: {
              "Content-Type": "application/json",
            },
            method: "POST",
          }
        );

        snackbar.showMessage({
          color: "deep-purple-accent-4",
          icon: "mdi-check-circle",
          text: response.data.message,
        });

        return response;
      } catch (error) {
        this.loading_change_debit_type = false;

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "mdi-close-circle",
          text: message,
        });

        throw error;
      }
    },
  },

  getters: {},
});
