<template>
  <v-container fluid class="pa-4 pa-md-6">
    <v-row class="d-flex justify-center mb-9">
      <v-col cols="12" sm="12" md="12" lg="12">
        <v-card class="mx-auto pos-card" width="100%">
          <v-data-table-server
            :headers="headers"
            :items="debtor_users"
            v-model:options="pagination"
            v-model:page="pagination.page"
            :items-per-page="pagination.itemsPerPage"
            :items-length="pageCount * pagination.itemsPerPage"
            :loading="loading"
            hide-default-footer
            fixed-header
            height="calc(100vh - 320px)"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:top>
              <div class="pa-4" style="border-bottom: 1px solid rgba(0,0,0,0.06);">
                <div class="d-flex align-center flex-wrap ga-3">
                  <h3 class="page-title">
                    <v-icon color="primary" class="me-2">mdi-clipboard-clock</v-icon>
                    جدول الديون
                  </h3>
                  <v-divider class="mx-2" inset vertical></v-divider>
                  <v-tooltip text="تحديث معلومات الجدول" location="bottom">
                    <template v-slot:activator="{ props }">
                      <v-btn @click="reset_table" icon variant="text" color="primary" v-bind="props">
                        <v-icon>mdi-refresh</v-icon>
                      </v-btn>
                    </template>
                  </v-tooltip>
                  <v-tooltip text="إضافة زبائن" location="bottom">
                    <template v-slot:activator="{ props }">
                      <v-btn @click="add_user" icon variant="text" color="primary" v-bind="props">
                        <v-icon>mdi-account-plus</v-icon>
                      </v-btn>
                    </template>
                  </v-tooltip>
                  <v-spacer></v-spacer>
                  <v-text-field
                    v-model="query"
                    @input="query_change"
                    append-inner-icon="mdi-magnify"
                    label="بحث"
                    class="font-weight-black"
                    color="primary"
                    variant="outlined"
                    rounded
                    clearable
                    hide-details
                    :style="$vuetify.display.smAndDown ? 'width: 100%;' : 'max-width: 360px; min-width: 200px;'"
                  />
                </div>
              </div>
            </template>
            <template v-slot:item="{ item }">
              <tr>
                <td class="text-center font-weight-black">
                  {{ item.name }}
                </td>
                <td class="text-center font-weight-black">
                  {{ item.phone }}
                </td>
                <td class="text-center font-weight-black">
                  {{ item.city }}
                </td>
                <td class="text-center font-weight-black">
                  <v-chip v-if="item.remaining_amount == 0" size="small" color="success" variant="tonal">
                    {{ $filters.formatNumber(item.remaining_amount) }} د.ع
                  </v-chip>
                  <v-chip v-else size="small" color="warning" variant="tonal">
                    {{ $filters.formatNumber(item.remaining_amount) }} د.ع
                  </v-chip>
                </td>
                <td class="text-center font-weight-black">
                  <h4 dir="ltr">
                    {{
                      $moment(item.updated_at)
                        .tz("Asia/Baghdad")
                        .format("YYYY-MM-DD hh:mm A")
                    }}
                  </h4>
                </td>

                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        color="primary"
                        @click="showPayments(item)"
                        :loading="loading_data == true && check_id == item.id"
                      >
                        <v-icon color="#5640a3" size="32">mdi-cash-multiple</v-icon>
                      </v-btn>
                    </template>
                    <span>كشف حساب</span>
                    <template v-slot:loader>
                      <span class="custom-loader">
                        <v-icon color="#5640a3">mdi-cached</v-icon>
                      </span>
                    </template>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        color="primary"
                        @click="updateInfoUser(item)"
                      >
                        <v-icon color="#37474F" size="32">mdi-account-edit</v-icon>
                      </v-btn>
                    </template>
                    <span>تعديل معلومات الزبون</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
          <div class="text-center py-3 py-sm-5 px-3 px-sm-4">
            <v-row dense>
              <v-col cols="12" sm="6">
                <v-pagination
                  v-model="pagination.page"
                  :length="pageCount"
                  :total-visible="$vuetify.display.xs ? 3 : 5"
                  rounded="circle"
                  variant="elevated"
                  density="comfortable"
                />
              </v-col>
              <v-col cols="12" sm="6">
                <v-select
                  v-model="pagination.itemsPerPage"
                  :items="items"
                  class="font-weight-black"
                  label="عدد العناصر"
                  color="primary"
                  variant="outlined"
                  rounded
                  persistent-hint
                  hide-details="auto"
                />
              </v-col>
            </v-row>
          </div>
        </v-card>
      </v-col>

      <PopShowPayments
        :dialog="dialog_show_payments"
        @popClose="dialog_show_payments = false"
      />
      <PopAddDebtorUsers
        :dialog="dialog_add_user"
        @popClose="dialog_add_user = false"
      />
      <PopUpdateInfoDebtorUser
        :dialog="dialog_update_info_user"
        :user="debtor_user"
        @popClose="dialog_update_info_user = false"
      />
      <CheckPassword :dialog="dialog2" @CheckPassword="dialog2 = false" />
    </v-row>
  </v-container>
</template>
<script setup>
import { ref, computed, watch } from "vue";
import { useDisplay } from "vuetify";
import { useDebitsStore } from "@/stores/debits";


import PopShowPayments from "@/components/debtor/PopShowPayments.vue";
import PopAddDebtorUsers from "@/components/debtor/PopAddUsers.vue";
import PopUpdateInfoDebtorUser from "@/components/debtor/PopUpdateInfoDebtorUser.vue";
import CheckPassword from "@/components/layout/CheckPassword.vue";


const debitsStore = useDebitsStore();
const { smAndDown } = useDisplay();

const items = [5, 10, 15, 20, 25];
const pagination = ref({ page: 1, itemsPerPage: 10, sortBy: [], sortDesc: [] });

const dialog_show_payments = ref(false);

const dialog2 = ref(false);
const check_id = ref(null);

// const dialog_add_info = ref(false);
const dialog_add_user = ref(false);
const loading_data = ref(false);

const dialog_update_info_user = ref(false);
const debtor_user = ref(null);

const headers = computed(() => {
  const m = smAndDown.value;
  return [
    { title: "الاسم", value: "name", align: "center", width: m ? "90px" : "150px" },
    { title: "رقم الهاتف", value: "barcode", align: "center", width: m ? "110px" : "190px" },
    { title: "المدينة", value: "purchase_price", align: "center", width: m ? "110px" : "190px" },
    { title: "الدين المتبقي", value: "created_at", align: "center", width: m ? "110px" : "190px" },
    { title: "اخر تحديث", value: "color", align: "center", width: m ? "90px" : "150px" },
    { title: "الدفعات", value: "color", align: "center", width: m ? "75px" : "130px" },
    { title: "العمليات", value: "color", align: "center", width: m ? "75px" : "130px" },
  ];
});

// ✅ Computed properties using Pinia state
const pageCount = computed(() => debitsStore.pageCount);

const query = computed({
  get: () => debitsStore.query,
  set: (val) => (debitsStore.query = val),
});
const params = computed({
  get: () => debitsStore.params,
  set: (val) => (debitsStore.params = val),
});
const status = computed({
  get: () => debitsStore.status,
  set: (val) => (debitsStore.status = val),
});

const date_from = computed({
  get: () => debitsStore.date_from,
  set: (val) => (debitsStore.date_from = val),
});

const date_to = computed({
  get: () => debitsStore.date_to,
  set: (val) => (debitsStore.date_to = val),
});

const debtor_users = computed(() => debitsStore.debtor_users);
const loading = computed(() => debitsStore.table_loading);



// ✅ Methods
function get_debtor_users() {
  const par = { ...pagination.value };
  params.value = par;
  debitsStore.get_debtor_users_with_sales_and_payment_dates();
}

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_debtor_users();
  }, 200);
}

function reset_table() {
  debitsStore.reset_table();
  debitsStore.get_debtor_users_with_sales_and_payment_dates();
}


function updateInfoUser(item) {
  debtor_user.value = item;
  dialog_update_info_user.value = true;
}



async function showPayments(item) {
  loading_data.value = true;
  check_id.value = item.id;
  debitsStore.id = item.id;

  debitsStore.sales_debtor = [];
  debitsStore.params_debtor.page = 1;
  debitsStore.debtor_state = "done";
  debitsStore.loading_debtor = false;

  await debitsStore.get_statistics_debtor_user();
  await debitsStore.get_sales_to_debtor();

  loading_data.value = false;
  dialog_show_payments.value = true;
}

async function add_user() {
  dialog_add_user.value = true;
}




// ✅ Watch pagination to refetch data
watch(
  pagination,
  () => {
    get_debtor_users();
  },
  { deep: true }
);

watch(query, (newVal) => {
  if (newVal === null || newVal === "") {
    pagination.value.page = 1;
    get_debtor_users();
  }
});

watch(status, (newVal) => {
  if (newVal && typeof newVal === "object" && newVal.value) {
    get_debtor_users();
  }
});

watch(date_from, (newVal) => {
  if (newVal != null && newVal != "") {
    get_debtor_users();
  }
});
watch(date_to, (newVal) => {
  if (newVal != null && newVal != "") {
    get_debtor_users();
  }
});
</script>
<style scoped>
.pos-card {
  border: 1px solid rgba(98,79,198,0.06);
  overflow: hidden;
}
.page-title {
  font-weight: 800;
  color: #1a1a2e;
  white-space: nowrap;
  display: flex;
  align-items: center;
}
</style>
