<template>
  <v-container fluid class="pa-4 pa-md-6">
    <v-row class="d-flex justify-center">
      <v-col cols="12">
        <v-card class="mx-auto pos-card" width="100%">
          <v-data-table-server
            :headers="headers"
            :items="sales"
            v-model:options="pagination"
            v-model:page="pagination.page"
            :items-per-page="pagination.itemsPerPage"
            :items-length="pageCount * pagination.itemsPerPage"
            :loading="loading"
            hide-default-footer
            fixed-header
            height="calc(100vh - 320px)"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:top>
              <div class="pa-4" style="border-bottom: 1px solid rgba(0,0,0,0.06);">
                <div class="d-flex align-center flex-wrap ga-3">
                  <h3 class="page-title">
                    <v-icon color="primary" class="me-2">mdi-truck-fast</v-icon>
                    جدول مبيعات التوصيل
                  </h3>
                  <v-tooltip text="تحديث معلومات الجدول" location="bottom">
                    <template v-slot:activator="{ props }">
                      <v-btn @click="reset_table" icon variant="text" color="primary" v-bind="props">
                        <v-icon>mdi-refresh</v-icon>
                      </v-btn>
                    </template>
                  </v-tooltip>
                  <v-spacer></v-spacer>
                  <v-text-field
                    v-model="barcode_query"
                    @input="query_change"
                    append-inner-icon="mdi-magnify"
                    label="بحث"
                    class="font-weight-black"
                    color="primary"
                    variant="outlined"
                    density="compact"
                    rounded
                    clearable
                    hide-details
                    :style="$vuetify.display.smAndDown ? 'width: 100%;' : 'max-width: 360px; min-width: 200px;'"
                  />
                </div>
              </div>
            </template>
            <template v-slot:item="{ item }">
              <tr>
                <td class="text-center font-weight-black">
                  <span v-if="item.name != null">{{ item.name }}</span>
                  <v-chip v-else size="small" color="error" variant="tonal">لايوجد</v-chip>
                </td>
                <td class="text-center font-weight-black">
                  {{ item.invoice_number }}
                </td>
                <td class="text-center font-weight-black">
                  {{ $filters.formatNumber(item.total) }} د.ع
                </td>
                <td class="text-center font-weight-black" dir="ltr">
                  {{
                    $moment(item.created_at)
                      .tz("Asia/Baghdad")
                      .format("YYYY-MM-DD hh:mm A")
                  }}
                </td>
                <td class="text-center font-weight-black">
                  <v-chip v-if="item.retrieve == 1" size="small" color="error" variant="tonal">راجعة كليًا</v-chip>
                  <v-chip v-else-if="item.partial_return" size="small" color="warning" variant="tonal">راجعة جزئيًا</v-chip>
                  <v-chip v-else size="small" color="success" variant="tonal">مكتملة</v-chip>
                </td>
                <td class="text-center font-weight-black">
                  <v-chip v-if="item.sale_type_delivery == 0" size="small" color="warning" variant="tonal">قيد التوصيل</v-chip>
                  <v-chip v-else-if="item.sale_type_delivery == 1" size="small" color="success" variant="tonal">تم التوصيل</v-chip>
                </td>

                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#624fc6"
                        @click="showItems(item.sale_items)"
                      >
                        <v-icon color="#624fc6" size="32">mdi-clipboard-text</v-icon>
                      </v-btn>
                    </template>
                    <span>عرض عناصر الفاتورة</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#D32F2F"
                        :disabled="item.retrieve == 1"
                        @click="popRetrieveAllItems(item.id)"
                        :loading="retrieve_loading && item.id === sale_id"
                      >
                        <v-icon color="#D32F2F" size="32">mdi-clipboard-remove</v-icon>
                        <template v-slot:loader>
                          <span class="custom-loader">
                            <v-icon color="#D32F2F">mdi-cached</v-icon>
                          </span>
                        </template>
                      </v-btn>
                    </template>
                    <span>استرجاع كامل</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        @click="printInvoice(item)"
                      >
                        <v-icon color="#37474F" size="32">mdi-printer</v-icon>
                      </v-btn>
                    </template>
                    <span>طباعة الفاتورة</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip
                    location="bottom"
                    interactive
                    v-if="item.name == null"
                  >
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        @click="popAddInfoCustomer(item.id)"
                        :loading="
                          loading_info_customer && item.id === id_info_sale
                        "
                      >
                        <v-icon color="#D32F2F" size="32">mdi-account-alert</v-icon>
                      </v-btn>
                    </template>
                    <span>اضافة معلومات الزبون</span>
                  </v-tooltip>

                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        :disabled="item.name == null && item.city == null"
                        @click="showInfoUser(item)"
                      >
                        <v-icon color="#4A148C" size="32">mdi-monitor</v-icon>
                      </v-btn>
                    </template>
                    <span>معلومات الزبون</span>
                  </v-tooltip>

                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        @click="changeTypeDelivery(item.id)"
                        :disabled="item.sale_type_delivery == 1"
                        :loading="
                          loading_delivery && item.id === id_sale_delivery
                        "
                      >
                        <v-icon color="#37474F" size="32">mdi-swap-horizontal-circle</v-icon>
                      </v-btn>
                    </template>
                    <span>تغير حالة التوصيل</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
          <div class="text-center py-3 py-sm-5 px-3 px-sm-4">
            <v-row dense>
              <v-col cols="12" sm="6">
                <v-pagination
                  v-model="pagination.page"
                  :length="pageCount"
                  :total-visible="$vuetify.display.xs ? 3 : 5"
                  rounded="circle"
                  variant="elevated"
                  active-color="primary"
                  density="comfortable"
                />
              </v-col>
              <v-col cols="12" sm="6">
                <v-select
                  v-model="pagination.itemsPerPage"
                  :items="items"
                  class="font-weight-black"
                  label="عدد العناصر"
                  color="primary"
                  variant="outlined"
                  rounded
                  persistent-hint
                  hide-details="auto"
                />
              </v-col>
              <v-col cols="6" sm="3">
                <Selects
                  v-on:update-value="status = $event"
                  v-model="status"
                  label="حالات البيع"
                  itemValue="value"
                  itemText="type"
                  :items="statuses"
                />
              </v-col>
              <v-col cols="6" sm="3">
                <Selects
                  v-on:update-value="sale_type_delivery = $event"
                  v-model="sale_type_delivery"
                  label="حالة التوصيل"
                  itemValue="value"
                  itemText="type"
                  :items="sale_types_delivery"
                />
              </v-col>
              <v-col cols="6" sm="3">
                <InputDate
                  v-model="date_from"
                  @clearInput="date_from = null"
                  label="من تاريخ"
                />
              </v-col>
              <v-col cols="6" sm="3">
                <InputDate
                  v-model="date_to"
                  @clearInput="date_to = null"
                  label="الى"
                />
              </v-col>
            </v-row>
          </div>
        </v-card>
      </v-col>
      <ShowItems
        :dialog="dialog"
        @popClose="dialog = false"
        :items="product_items"
        @itemUpdated="updateProductItems"
      />
      <PopRetrieveAllItems
        :dialog="dialog_retrieve_all_items"
        @popClose="dialog_retrieve_all_items = false"
        @retrieveAllItems="retrieveAllItems"
      />

      <PopSalesDelivery
        :dialog="dialog_delivery"
        @popClose="dialog_delivery = false"
        @changeDelivery="change_delivery"
      />

      <PopShowInfoUser
        :dialog="dialog_info_user"
        :info_user="info_user"
        @popClose="dialog_info_user = false"
      />
      <PopSalesDebitOrDelivery
        :dialog="dialog_add_info"
        @popClose="dialog_add_info = false"
        @addSales="addInfoCustomer"
      />
    </v-row>
  </v-container>
</template>
<script setup>
import { ref, computed, watch } from "vue";
import { useDisplay } from "vuetify";
import { useSalesDeliveryStore } from "@/stores/sale_delivery";
import InvoiceReceipt from "@/components/layout/invoice.vue";
import Selects from "@/components/layout/Selects.vue";
import InputDate from "@/components/layout/InputDate.vue";
import ShowItems from "@/components/sales/ShowItems.vue";
import PopRetrieveAllItems from "@/components/sales/PopRetrieveAllItems.vue";
import PopSalesDelivery from "@/components/sales/PopSalesDelivery.vue";
import PopShowInfoUser from "@/components/sales/PopShowInfoUser.vue";
import PopSalesDebitOrDelivery from "@/components/sales/PopSalesDebitOrDelivery.vue";

import { h, render } from "vue";
import { nextTick } from "vue";
// import { server } from "@/config";

const salesStore = useSalesDeliveryStore();
const { smAndDown } = useDisplay();


const items = [5, 10, 15, 20, 25,50,100,200];
const pagination = ref({ page: 1, itemsPerPage: 10, sortBy: [], sortDesc: [] });
const dialog = ref(false);
const dialog_retrieve_all_items = ref(false);
const product_items = ref([]);
const sale_id = ref(null);
const id_info_sale = ref(null);
const id_sale_delivery = ref(null);
const dialog_delivery = ref(false);

const dialog_info_user = ref(false);
const info_user = ref(null);
const dialog_add_info = ref(false);

const statuses = [
  { type: "مكتملة", value: "completed" },
  { type: "راجعة كليًا", value: "full_return" },
  { type: "راجعة جزئيًا", value: "partial_return" },
];

const sale_types_delivery = [
  { type: "قيد التوصيل", value: "progress" },
  { type: "تم التوصيل", value: "delivered" },
];

const headers = computed(() => {
  const m = smAndDown.value;
  return [
    { title: "الاسم", value: "name", align: "center", width: m ? "90px" : "150px" },
    { title: "باركود", value: "barcode", align: "center", width: m ? "110px" : "190px" },
    { title: "المجموع الكلي ", value: "purchase_price", align: "center", width: m ? "110px" : "190px" },
    { title: "التاريخ", value: "created_at", align: "center", width: m ? "110px" : "190px" },
    { title: "حالة البيع", value: "color", align: "center", width: m ? "90px" : "150px" },
    { title: "حالة التوصيل", value: "sale_type_delivery", align: "center", width: m ? "90px" : "150px" },
    { title: "عرض العناصر", value: "color", align: "center", width: m ? "75px" : "130px" },
    { title: "استرجاع", value: "color", align: "center", width: m ? "75px" : "130px" },
    { title: "الفاتورة", value: "name", align: "center", width: m ? "95px" : "160px" },
    { title: "العمليات", value: "name", align: "center", width: m ? "105px" : "180px" },
  ];
});

// ✅ Computed properties using Pinia state
const pageCount = computed(() => salesStore.pageCount);

const barcode_query = computed({
  get: () => salesStore.barcode_query,
  set: (val) => (salesStore.barcode_query = val),
});
const params = computed({
  get: () => salesStore.params,
  set: (val) => (salesStore.params = val),
});
const status = computed({
  get: () => salesStore.status,
  set: (val) => (salesStore.status = val),
});
const sale_type_delivery = computed({
  get: () => salesStore.sale_type_delivery,
  set: (val) => (salesStore.sale_type_delivery = val),
});
const date_from = computed({
  get: () => salesStore.date_from,
  set: (val) => (salesStore.date_from = val),
});

const date_to = computed({
  get: () => salesStore.date_to,
  set: (val) => (salesStore.date_to = val),
});

const sales = computed(() => salesStore.sales_delivery);
const loading = computed(() => salesStore.table_loading);
const loading_delivery = computed(
  () => salesStore.change_type_delivery_loading
);
const retrieve_loading = computed(() => salesStore.retrieve_loading);
const loading_info_customer = computed(() => salesStore.loading_info_customer);

// ✅ Methods
function get_sales_delivery() {
  const par = { ...pagination.value };
  params.value = par;
  salesStore.get_sales_delivery();
}

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_sales_delivery();
  }, 200);
}

function reset_table() {
  salesStore.reset_table();
  salesStore.get_sales_delivery();
}

function showItems(items) {
  product_items.value = items;
  dialog.value = true;
}

function changeTypeDelivery(id) {
  id_sale_delivery.value = id;
  dialog_delivery.value = true;
}

function updateProductItems(updatedSale) {
  product_items.value = updatedSale.sale_items;
}

function popRetrieveAllItems(id) {
  sale_id.value = id;
  dialog_retrieve_all_items.value = true;
}

function showInfoUser(item) {
  info_user.value = item;
  dialog_info_user.value = true;
}

const change_delivery = async () => {
  dialog_delivery.value = false;
  let data = {
    sale_id: id_sale_delivery.value,
  };
  try {
    await salesStore.change_type_delivery(data);
    id_sale_delivery.value = null;
  } catch (e) {
    // error already handled in store
  }
};
const retrieveAllItems = async () => {
  dialog_retrieve_all_items.value = false;
  let data = {
    sale_id: sale_id.value,
  };
  try {
    await salesStore.retrieve_all_items(data);
    sale_id.value = null;
  } catch (e) {
    // error already handled in store
  }
};
async function popAddInfoCustomer(id) {
  dialog_add_info.value = true;
  id_info_sale.value = id;
}

async function addInfoCustomer(info_user) {
  dialog_add_info.value = false;
  if (!info_user) return;

  const data = {
    sale_id: id_info_sale.value,
    name: info_user.name,
    city: info_user.city,
    phone: info_user.phone,
  };

  try {
    await salesStore.add_info_customer(JSON.parse(JSON.stringify(data)));
  } catch (error) {
    console.error("حدث خطأ أثناء إضافة معلومات الزبون:", error);
  }
}

// طباعة فاتورة
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");
let isPrinting = false;

function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;

    // حاوية الطباعة المباشرة تحت body
  const container = document.createElement("div");
  container.id = "print-root"; // مهم جداً للـ CSS أدناه
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);

  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };


  const vnode = h(InvoiceReceipt, {
    purchasedItems: items.sale_items,
    nameStore: nameStore.value,
    paperSize: paperSize.value, // أو size-80 حسب الحاجة
    saleType: items.sale_type,
    invoiceId: items.invoice_number,
    date: items.updated_at,
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print(); // نسخة واحدة فقط
      });
    },
  });

  render(vnode, container);
  
}

// ✅ Watch pagination to refetch data
watch(
  pagination,
  () => {
    get_sales_delivery();
  },
  { deep: true }
);

watch(barcode_query, (newVal) => {
  if (newVal === null || newVal === "") {
    pagination.value.page = 1;
    get_sales_delivery();
  }
});

watch(status, (newVal) => {
  if (newVal && typeof newVal === "object" && newVal.value) {
    get_sales_delivery();
  }
});
watch(sale_type_delivery, (newVal) => {
  if (newVal && typeof newVal === "object" && newVal.value) {
    get_sales_delivery();
  }
});
watch(date_from, (newVal) => {
  if (newVal != null && newVal != "") {
    get_sales_delivery();
  }
});
watch(date_to, (newVal) => {
  if (newVal != null && newVal != "") {
    get_sales_delivery();
  }
});
</script>
<style scoped>
.pos-card {
  border: 1px solid rgba(98,79,198,0.06);
  overflow: hidden;
}
.page-title {
  font-weight: 800;
  color: #1a1a2e;
  white-space: nowrap;
  display: flex;
  align-items: center;
}
</style>
