<template>
  <v-dialog
    :model-value="dialog"
    fullscreen
    transition="dialog-bottom-transition"
  >
    <v-card class="add-goods-card">
      <!-- Header -->
      <div class="dialog-header">
        <div class="d-flex align-center justify-space-between px-5 py-4">
          <div class="d-flex align-center">
            <div class="header-icon me-3">
              <v-icon color="white" size="24">mdi-plus-box</v-icon>
            </div>
            <div>
              <h3 class="text-white">إضافة منتجات</h3>
              <p class="text-white mt-n1" style="opacity: 0.7; font-size: 0.8rem;">أدخل بيانات المنتج الجديد</p>
            </div>
          </div>
          <v-btn icon variant="text" @click="$emit('popClose')">
            <v-icon color="white" size="24">mdi-close</v-icon>
          </v-btn>
        </div>
      </div>

      <v-form ref="add_goods_form">
        <div class="pa-5 pa-md-8">
          <!-- Section 1: Basic Info -->
          <div class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-information-outline</v-icon>
              معلومات المنتج الأساسية
            </h4>
            <v-row>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">اسم المنتج</label>
                <Input
                  v-model="product"
                  @update-value="product = $event"
                  autocomplete="product"
                  type="text"
                  label="اسم المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">نوع المنتج</label>
                <Selects
                  v-on:update-value="type = $event"
                  v-model="type"
                  label="نوع المنتج"
                  itemValue="value"
                  itemText="type"
                  :items="types"
                  :rules="AllRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">باركود المنتج</label>
                <Input
                  v-model="barcode"
                  @update-value="barcode = $event"
                  type="text"
                  label="باركود المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">الموديل</label>
                <Input
                  v-model="model"
                  @update-value="model = $event"
                  type="number"
                  label="الموديل (اختياري)"
                />
              </v-col>
            </v-row>
          </div>

          <!-- Section 2: Pricing & Color -->
          <div class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-cash-multiple</v-icon>
              التسعير واللون
            </h4>
            <v-row align="center">
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">سعر الشراء</label>
                <Input
                  v-model="purchase_price"
                  @update-value="purchase_price = $event"
                  autocomplete="purchase_price"
                  type="Number"
                  label="سعر الشراء"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">سعر البيع</label>
                <v-text-field
                  :model-value="displayPrice"
                  type="text"
                  label="سعر البيع"
                  class="font-weight-bold"
                  clearable
                  :rules="NameRulse"
                  @update:modelValue="onInput"
                  @keypress="allowOnlyNumbers"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">عدد القطع الكلي</label>
                <Input
                  v-model="total_pieces"
                  @update-value="total_pieces = $event"
                  autocomplete="total_pieces"
                  type="Number"
                  label="عدد القطع"
                  :rules="AllRulse"
                  :min="1"
                  :max="30"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">لون المنتج</label>
                <div class="color-picker-wrapper">
                  <VSwatches v-model="color" :swatches="swatches" />
                  <div class="color-preview" :style="{ background: color }" />
                </div>
              </v-col>
            </v-row>
          </div>

          <!-- Section 3: Sizes (dynamic) -->
          <div v-if="sizes.length > 0" class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-ruler</v-icon>
              المقاسات والكميات
              <v-chip size="small" color="primary" variant="tonal" class="ms-2">{{ sizes.length }}</v-chip>
            </h4>
            <v-row dense>
              <template v-for="(size, index) in sizes" :key="index">
                <v-col cols="6" sm="4" md="2">
                  <div class="size-card">
                    <span class="size-number">#{{ index + 1 }}</span>
                    <Input
                      v-model="size.size"
                      @update-value="size.size = $event"
                      autocomplete="size"
                      type="text"
                      label="المقاس"
                      :rules="SizeRulse"
                    />
                  </div>
                </v-col>
                <v-col cols="6" sm="4" md="2">
                  <div class="size-card">
                    <Input
                      v-model="size.quantity"
                      @update-value="size.quantity = $event"
                      autocomplete="label"
                      type="Number"
                      label="الكمية"
                      :rules="AllRulse"
                    />
                  </div>
                </v-col>
              </template>
            </v-row>
          </div>

          <!-- Submit -->
          <div class="d-flex justify-center mt-4 mb-2">
            <v-btn
              @click="add_goods"
              :loading="loading"
              color="primary"
              size="x-large"
              rounded="lg"
              elevation="2"
              min-width="240"
            >
              <v-icon class="me-2">mdi-check-circle</v-icon>
              إضافة المنتج
              <template v-slot:loader>
                <v-progress-circular indeterminate size="22" width="2" color="white" />
              </template>
            </v-btn>
          </div>
        </div>
      </v-form>
    </v-card>
  </v-dialog>
</template>

<script setup>
import { ref, watch, computed } from "vue";
import Input from "../layout/Input.vue";
import Selects from "../layout/Selects.vue";
import { useGoodsStore } from "@/stores/goods";
const goodsStore = useGoodsStore();

defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
});
const swatches = [
  "#000000", "#FFFFFF", "#FF0000", "#00FF00", "#0000FF", "#4B0082",
  "#FFFF00", "#800080", "#00FFFF", "#FFC0CB", "#FFA500", "#808080",
  "#A52A2A", "#FFD700", "#C0C0C0", "#800000", "#8B4000", "#826644",
];
const add_goods_form = ref(null);
const type = ref(null);
const barcode = ref(null);
const purchase_price = ref(null);
const selling_price = ref(null);
const model = ref(null);
const color = ref("#000000");
const product = ref("");
const total_pieces = ref(0);
const sizes = ref([]);
const types = [
  { name: "type", type: "ملابس", value: 0 },
  { name: "type", type: "احذية", value: 1 },
];

const NameRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 3 || "الحد الادنى لعدد الاحرف هوه 3",
];

const SizeRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 1 || "الحد الادنى لعدد الاحرف هوه 1",
  (value) => (value || "").length <= 3 || "الحد الاقصى لعدد الاحرف هوه 3",
];

const AllRulse = [(value) => !!value || "هذا الحقل مطلوب"];

const add_goods = async () => {
  const isValid = await add_goods_form.value.validate();
  if (isValid.valid) {
    const variants = sizes.value.map((v, idx) => {
      return {
        index: idx,
        size: v.size,
        quantity: Number(v.quantity) || 0,
      };
    });

    let data = {
      name: product.value,
      type: type.value?.value,
      barcode: barcode.value,
      total_pieces: total_pieces.value,
      color: color.value,
      purchase_price: purchase_price.value,
      selling_price: selling_price.value,
      variants: variants,
      model: model.value,
    };

    try {
      await goodsStore.add_goods(data);
      add_goods_form.value.reset();
      sizes.value = [];
      total_pieces.value = 0;
    } catch (e) {
      console.error("Error in store", e);
    }
  }
};

const displayPrice = computed(() => {
  if (!selling_price.value) return "";
  return new Intl.NumberFormat("en-US").format(Number(selling_price.value));
});

const onInput = (val) => {
  const str = (val ?? "").toString();
  selling_price.value = str.replace(/\D/g, "");
};

const allowOnlyNumbers = (event) => {
  const key = event.key;
  if (!/^[0-9]$/.test(key)) event.preventDefault();
};

const loading = computed(() => goodsStore.add_product_loading);

watch(total_pieces, (newVal) => {
  const currentLength = sizes.value.length;
  if (newVal > currentLength) {
    for (let i = currentLength; i < newVal; i++) {
      sizes.value.push({ size: "", quantity: null, index: i });
    }
  } else if (newVal < currentLength) {
    sizes.value.splice(newVal);
  }
  sizes.value.forEach((s, idx) => { s.index = idx; });
});
</script>

<style scoped>
.add-goods-card {
  border-radius: 0 !important;
}

.dialog-header {
  background: linear-gradient(135deg, #624fc6 0%, #1f2544 100%);
  position: sticky;
  top: 0;
  z-index: 10;
}

.header-icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
}

.form-section {
  background: #faf9fe;
  border-radius: 16px;
  padding: 24px;
  border: 1px solid rgba(98, 79, 198, 0.06);
}

.section-label {
  font-weight: 700;
  color: #1a1a2e;
  display: flex;
  align-items: center;
  font-size: 1rem;
}

.field-label {
  display: block;
  font-weight: 600;
  font-size: 0.82rem;
  color: #64607d;
  margin-bottom: 4px;
}

.color-picker-wrapper {
  display: flex;
  align-items: center;
  gap: 12px;
}

.color-preview {
  width: 40px;
  height: 40px;
  border-radius: 10px;
  border: 2px solid rgba(0, 0, 0, 0.1);
  flex-shrink: 0;
}

.size-card {
  position: relative;
  padding-top: 4px;
}

.size-number {
  position: absolute;
  top: -4px;
  right: 8px;
  font-size: 0.7rem;
  font-weight: 700;
  color: #624fc6;
  z-index: 1;
}

@media (max-width: 600px) {
  .form-section {
    padding: 16px;
    border-radius: 12px;
  }
  .header-icon {
    width: 36px;
    height: 36px;
    border-radius: 10px;
  }
}
</style>
