<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      max-width="600"
    >
      <v-card class="mx-auto card" width="100%">
        <v-toolbar dark color="#624fc6">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <v-icon color="#ffffff" size="25">mdi-close</v-icon>
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
            <h4 style="font-family: 'Cairo', sans-serif">
              تعديل معلومات مستخدم
            </h4>
          </v-toolbar-title>
        </v-toolbar>
        <v-card-text class="mt-4 d-flex justify-stert">
          <v-row>
            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="user_info.name"
                @update-value="user_info.name = $event"
                autocomplete="name"
                type="text"
                label="اسم الزبون"
              />
            </v-col>

            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="user_info.city"
                @update-value="user_info.city = $event"
                autocomplete="city"
                type="text"
                label="المدينة"
              />
            </v-col>

            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="user_info.phone"
                @update-value="user_info.phone = $event"
                autocomplete="phone"
                type="number"
                label="رقم الهاتف"
              />
            </v-col>
          </v-row>
        </v-card-text>
        <v-card-actions class="mt-5 pb-5">
          <v-btn
            size="large"
            v-on:click="update_user"
            color="#624fc6"
            class="px-16 mx-auto border-btn"
            elevation="4"
            variant="flat"
            :loading="loading"
          >
            <h4 style="color: white; font-size: 17px">تعديل</h4>
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
import Input from "@/components/layout/Input.vue";
import { ref, watch, defineEmits, computed, defineProps } from "vue";
const emit = defineEmits(["popClose"]);
import { useDebitsStore } from "@/stores/debits";
const debitsStore = useDebitsStore();

const user_info = ref(null);

const props = defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  user: {
    type: Object,
    default: null,
  },
});

const loading = computed(() => debitsStore.loading_update_user);

async function update_user() {
  let data = {
    id: user_info.value.id,
    name: user_info.value.name,
    city: user_info.value.city,
    phone: user_info.value.phone,
  };
  try {
    await debitsStore.update_debtor_users(data);
  } catch (error) {
    console.error("حدث خطأ أثناء إضافة المستخدم:", error);
  }
  emit("popClose");
}

const currentItemId = ref(null);

watch(
  () => props.user,
  (newVal) => {
    if (newVal && typeof newVal === "object") {
      // فقط إذا تغير المعرف id للعنصر، نفذ التهيئة
      if (currentItemId.value !== newVal.id) {
        currentItemId.value = newVal.id;

        user_info.value = {
          ...newVal,
          items: Array.isArray(newVal.items) ? [...newVal.items] : [],
        };
      }
    }
  },
  { immediate: true, deep: true }
);
</script>
<style scoped>
.card {
  border-radius: 25px !important;
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
