<template>
  <v-dialog
    :model-value="dialog"
    fullscreen
    transition="dialog-bottom-transition"
  >
    <v-card class="edit-goods-card">
      <!-- Header -->
      <div class="dialog-header">
        <div class="d-flex align-center justify-space-between px-5 py-4">
          <div class="d-flex align-center">
            <div class="header-icon me-3">
              <v-icon color="white" size="24">mdi-pencil</v-icon>
            </div>
            <div>
              <h3 class="text-white">تعديل المنتجات</h3>
              <p class="text-white mt-n1" style="opacity: 0.7; font-size: 0.8rem;">تعديل بيانات المنتج</p>
            </div>
          </div>
          <v-btn icon variant="text" @click="$emit('popClose')">
            <v-icon color="white" size="24">mdi-close</v-icon>
          </v-btn>
        </div>
      </div>

      <v-form ref="edit_goods_form">
        <div class="pa-5 pa-md-8">
          <!-- Section 1: Basic Info -->
          <div class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-information-outline</v-icon>
              معلومات المنتج الأساسية
            </h4>
            <v-row>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">اسم المنتج</label>
                <Input
                  v-model="item_info.product.name"
                  @update-value="item_info.product.name = $event"
                  type="text"
                  label="اسم المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">نوع المنتج</label>
                <Selects
                  v-model="type"
                  @update-value="type = $event"
                  label="نوع المنتج"
                  itemValue="value"
                  itemText="type"
                  :items="types"
                  :rules="AllRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">باركود المنتج</label>
                <Input
                  v-model="item_info.barcode"
                  @update-value="item_info.barcode = $event"
                  type="text"
                  label="باركود المنتج"
                  :rules="NameRulse"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">الموديل</label>
                <Input
                  v-model="item_info.model"
                  @update-value="item_info.model = $event"
                  type="number"
                  label="الموديل (اختياري)"
                />
              </v-col>
            </v-row>
          </div>

          <!-- Section 2: Pricing & Color -->
          <div class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-cash-multiple</v-icon>
              التسعير واللون
            </h4>
            <v-row align="center">
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">سعر الشراء</label>
                <Input
                  v-model="item_info.purchase_price"
                  @update-value="item_info.purchase_price = $event"
                  type="Number"
                  label="سعر الشراء"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">سعر البيع</label>
                <v-text-field
                  :model-value="displaySellingPrice"
                  type="text"
                  label="سعر البيع"
                  class="font-weight-bold"
                  clearable
                  :rules="NameRulse"
                  @update:modelValue="(val) => (displaySellingPrice = val)"
                  @keypress="allowOnlyNumbers"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">عدد القطع الكلي</label>
                <Input
                  v-model="item_info.total_pieces"
                  @update-value="item_info.total_pieces = Number($event)"
                  type="Number"
                  label="عدد القطع"
                  :rules="AllRulse"
                  :min="1"
                  :max="30"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3">
                <label class="field-label">لون المنتج</label>
                <div class="color-picker-wrapper">
                  <VSwatches v-model="item_info.color" :swatches="swatches" />
                  <div class="color-preview" :style="{ background: item_info.color }" />
                </div>
              </v-col>
            </v-row>
          </div>

          <!-- Section 3: Sizes -->
          <div v-if="item_info.items && item_info.items.length > 0" class="form-section mb-6">
            <h4 class="section-label mb-4">
              <v-icon size="20" color="primary" class="me-2">mdi-ruler</v-icon>
              المقاسات والكميات
              <v-chip size="small" color="primary" variant="tonal" class="ms-2">{{ item_info.items.length }}</v-chip>
            </h4>
            <v-row dense>
              <template v-for="(sizeItem, index) in item_info.items" :key="index">
                <v-col cols="6" sm="4" md="2">
                  <div class="size-card">
                    <span class="size-number">#{{ index + 1 }}</span>
                    <Input
                      v-model="sizeItem.size"
                      @update-value="sizeItem.size = $event"
                      type="text"
                      :label="`المقاس`"
                      :rules="SizeRulse"
                    />
                  </div>
                </v-col>
                <v-col cols="6" sm="4" md="2">
                  <div class="size-card">
                    <Input
                      v-model="sizeItem.quantity"
                      @update-value="sizeItem.quantity = Number($event)"
                      type="Number"
                      :label="`الكمية`"
                      :rules="RulseQuantity"
                    />
                  </div>
                </v-col>
              </template>
            </v-row>
          </div>

          <!-- Submit -->
          <div class="d-flex justify-center mt-4 mb-2">
            <v-btn
              @click="edit_goods"
              :loading="loading"
              color="primary"
              size="x-large"
              rounded="lg"
              elevation="2"
              min-width="240"
            >
              <v-icon class="me-2">mdi-check-circle</v-icon>
              حفظ التعديلات
              <template v-slot:loader>
                <v-progress-circular indeterminate size="22" width="2" color="white" />
              </template>
            </v-btn>
          </div>
        </div>
      </v-form>
    </v-card>
  </v-dialog>
</template>

<script setup>
import { ref, watch, computed } from "vue";
import Input from "../layout/Input.vue";
import Selects from "../layout/Selects.vue";
import { useGoodsStore } from "@/stores/goods";

const goodsStore = useGoodsStore();
const emit = defineEmits(["popClose"]);
const props = defineProps({
  dialog: Boolean,
  item: Object,
});

const swatches = [
  "#000000","#FFFFFF","#FF0000","#00FF00","#0000FF","#FFFF00","#800080",
  "#00FFFF","#FFC0CB","#FFA500","#808080","#A52A2A","#FFD700","#C0C0C0",
  "#800000","#8B4000","#826644",
];

const edit_goods_form = ref(null);
const type = ref(null);

const types = [
  { name: "type", type: "ملابس", value: 0 },
  { name: "type", type: "احذية", value: 1 },
];

const item_info = ref({});

const NameRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 3 || "الحد الادنى لعدد الاحرف هوه 3",
];
const SizeRulse = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 1 || "الحد الادنى لعدد الاحرف هوه 1",
  (value) => (value || "").length <= 3 || "الحد الاقصى لعدد الاحرف هوه 3",
];
const AllRulse = [(value) => !!value || "هذا الحقل مطلوب"];

const RulseQuantity = [
  (value) =>
    (value !== null && value !== undefined && value !== "") ||
    "هذا الحقل مطلوب",
];

const edit_goods = async () => {
  const isValid = await edit_goods_form.value.validate();
  if (isValid.valid) {
    let data = {
      id_product: item_info.value.product.id,
      id_dozen: item_info.value.id,
      name: item_info.value.product.name,
      type: type.value.value,
      barcode: item_info.value.barcode,
      total_pieces: item_info.value.total_pieces,
      color: item_info.value.color,
      purchase_price: item_info.value.purchase_price,
      selling_price: item_info.value.selling_price,
      model: item_info.value.model,
      variants: item_info.value.items.map((item, index) => ({
        ...item,
        index: index + 1,
      })),
    };

    try {
      await goodsStore.edite_product(data);
      emit("popClose");
    } catch (e) {
      console.error("edit_product error:", e);
    }
  }
};

const loading = computed(() => goodsStore.edit_product_loading);

const displaySellingPrice = computed({
  get() {
    if (!item_info.value.selling_price) return "";
    return new Intl.NumberFormat("en-US").format(
      Number(item_info.value.selling_price)
    );
  },
  set(val) {
    item_info.value.selling_price = (val ?? "")
      .toString()
      .replace(/\D/g, "");
  },
});

const allowOnlyNumbers = (event) => {
  if (!/^[0-9]$/.test(event.key)) event.preventDefault();
};

watch(
  () => item_info.value.total_pieces,
  (newVal) => {
    if (!Array.isArray(item_info.value.items)) {
      item_info.value.items = [];
    }
    const currentLength = item_info.value.items.length;
    if (newVal > currentLength) {
      const diff = newVal - currentLength;
      for (let i = 0; i < diff; i++) {
        item_info.value.items.push({
          size: "",
          quantity: null,
          index: currentLength + i + 1,
        });
      }
    }
    if (newVal < currentLength) {
      item_info.value.items.splice(newVal);
    }
    item_info.value.items = item_info.value.items.map((it, idx) => ({
      ...it,
      index: idx + 1,
    }));
  }
);

const currentItemId = ref(null);
watch(
  () => props.item,
  (newVal) => {
    if (newVal && typeof newVal === "object") {
      if (currentItemId.value !== newVal.id) {
        currentItemId.value = newVal.id;
        item_info.value = {
          ...newVal,
          items: Array.isArray(newVal.items)
            ? newVal.items.map((it, idx) => ({ ...it, index: idx + 1 }))
            : [],
        };
        type.value =
          newVal.product.type == 1
            ? { name: "type", type: "احذية", value: 1 }
            : { name: "type", type: "ملابس", value: 0 };
      }
    }
  },
  { immediate: true, deep: true }
);
</script>

<style scoped>
.edit-goods-card {
  border-radius: 0 !important;
}

.dialog-header {
  background: linear-gradient(135deg, #624fc6 0%, #1f2544 100%);
  position: sticky;
  top: 0;
  z-index: 10;
}

.header-icon {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
}

.form-section {
  background: #faf9fe;
  border-radius: 16px;
  padding: 24px;
  border: 1px solid rgba(98, 79, 198, 0.06);
}

.section-label {
  font-weight: 700;
  color: #1a1a2e;
  display: flex;
  align-items: center;
  font-size: 1rem;
}

.field-label {
  display: block;
  font-weight: 600;
  font-size: 0.82rem;
  color: #64607d;
  margin-bottom: 4px;
}

.color-picker-wrapper {
  display: flex;
  align-items: center;
  gap: 12px;
}

.color-preview {
  width: 40px;
  height: 40px;
  border-radius: 10px;
  border: 2px solid rgba(0, 0, 0, 0.1);
  flex-shrink: 0;
}

.size-card {
  position: relative;
  padding-top: 4px;
}

.size-number {
  position: absolute;
  top: -4px;
  right: 8px;
  font-size: 0.7rem;
  font-weight: 700;
  color: #624fc6;
  z-index: 1;
}

@media (max-width: 600px) {
  .form-section {
    padding: 16px;
    border-radius: 12px;
  }
  .header-icon {
    width: 36px;
    height: 36px;
    border-radius: 10px;
  }
}
</style>
