<template>
  <v-dialog
    :model-value="dialog"
    width="100%"
    height="100%"
    persistent
    transition="dialog-bottom-transition"
  >
    <v-card class="mx-auto check-card" width="100%">
      <!-- Header -->
      <div class="check-header pa-6 text-center">
        <div class="lock-icon mx-auto mb-3">
          <v-icon color="white" size="36">mdi-lock</v-icon>
        </div>
        <h3 class="text-white">الرمز السري</h3>
        <p style="color: rgba(255,255,255,0.75); font-size: 0.9rem;" class="mt-1">
          أدخل الرمز السري لفك القفل
        </p>
      </div>

      <v-card-text class="pa-6 d-flex justify-center">
        <v-col cols="12" sm="8" md="5" lg="4">
          <v-text-field
            v-model="password"
            :type="showPassword ? 'text' : 'password'"
            label="كلمة المرور"
            autocomplete="current-password"
            :append-inner-icon="showPassword ? 'mdi-eye-outline' : 'mdi-eye-off-outline'"
            @click:append-inner="showPassword = !showPassword"
            prepend-inner-icon="mdi-lock-outline"
            :rules="PasswordsRules"
            @keyup.enter="checkPassword"
          />
        </v-col>
      </v-card-text>

      <v-card-actions class="pb-8 px-6 justify-center">
        <v-btn
          size="x-large"
          color="primary"
          rounded="lg"
          elevation="2"
          class="px-16"
          @click="checkPassword"
        >
          <v-icon size="22" class="me-2">mdi-check-circle</v-icon>
          تأكيد
        </v-btn>
      </v-card-actions>
    </v-card>
  </v-dialog>
</template>

<script setup>
import { ref } from "vue";
import { useSnackbarStore } from "@/stores/snackbar";

const PasswordsRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 8 || "الحد الادنى لعدد الاحرف هوه 8",
];

const emit = defineEmits(["CheckPassword"]);

const password = ref(null);
const showPassword = ref(false);

defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
});

function checkPassword() {
  if (password.value == "fffjjjqq") {
    emit("CheckPassword", false);
  } else {
    const snackbar = useSnackbarStore();
    snackbar.showMessage({
      color: "#B71C1C",
      icon: "mdi-close-circle",
      text: "الرمز السري غير صحيح",
    });
  }
}
</script>

<style scoped>
.check-card {
  overflow: hidden;
}

.check-header {
  background: linear-gradient(135deg, #624fc6 0%, #1f2544 100%);
}

.lock-icon {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
}
</style>
